INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3059, 'question-system-analyst-2024-11-case-11983', '系统分析师', '结构化设计', 2024, '2024年11月系统分析师案例分析-软件需求工程', '阅读以下关于软件维护的叙述，在答题纸上回答问题1至问题3。

【说明】

某企业自主研发了超市自助结算系统具备以下主要功能：

自动计价：顾客在结算时，通过自助设备扫描商品条码，系统能够快速识别商品，在屏幕上清晰显示商品的名称、规格、单价等详细信息，同时系统自动计算商品总价，并将结果返回显示在屏幕上，供顾客确认。

付款管理：当顾客完成商品选购并确认总价后，可选择多种付款方式（如现金、银行卡、移动支付等）进行付款。付款成功后，财务清算系统会及时接收到支付完成的通知，并进行相应的账务处理。

库存管理：一旦交易成功，系统会依据订单中的商品信息，自动对库存商品数量进行相应减少操作，并将变动情况准确记入库存表中，以确保库存数据的实时性和准确性，为后续的采购和销售决策提供可靠依据。

交易管理：系统会全面、准确地记录每一笔交易的详细信息，包括交易时间、顾客信息、商品清单、付款金额、付款方式等。这些记录将被妥善保存，以便在后续需要时（如顾客查询、财务审计、数据分析等）能够快速、便捷地进行查询和调用。

---
### 问题 1

（10 分）请用300字分别介绍流程图和数据流图并比较它们的不同之处。', '[]', '', '①. 数据流图作为一种图形化工具，说明业务处理过程、系统边界内所包含的功能、系统中的数据流，适用于【系统分析中的逻辑建模阶段】；
②. 流程图以图形化方式展示应用程序从数据输入到获得输出为止的逻辑过程，描述处理过程的控制流，往往【涉及具体技术、环境，适用于系统设计中的物理建模阶段】

区别：
①. 数据流图的处理过程【可并行】；流程图在某时间点只能处于【一个处理过程】
②. 数据流图展现系统的【数据流】；流程图展现系统的【控制流】
③. 数据流图展现【全局处理过程】，过程间遵循【不同的计时标准）；流程图的处理过程遵循【一致的计时标准】 

此题难度中等，毕竟数据流图是系分反复要背的内容，所以都比较熟悉。流程图大家用的比较多，也能说上一点。这里的关键是，对比的时候要说清楚两者的关注点不同，数据流图是数据流动，流程图是流程控制等接近的意思。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-03-28 12:06:33', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3060, 'question-system-analyst-2024-11-case-11984', '系统分析师', '结构化设计', 2024, '2024年11月系统分析师案例分析-软件需求工程', '阅读以下关于软件维护的叙述，在答题纸上回答问题1至问题3。

