INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3064, 'question-system-analyst-2024-11-case-11988', '系统分析师', '数据库范式', 2024, '2024年11月系统分析师案例分析-数据库系统', '阅读以下关于数据库设计的叙述，在答题纸上回答问题1至问题3。

【说明】

某公司为了鼓励员工考取技能证书，提升公司竞争力，准备设计一套技能需求水平管理系统。王工在设计之处进行了系统分析，建立了以下数据库模型：

技能表（技能ID、技能描述），主键是技能 ID；

员工表（员工ID、姓名、部门、联系方式），主键是员工 ID；

项目表（项目ID、项目名称、项目描述）、主键是项目ID；

员工技能表（员工ID、技能ID、技能水平）；

项目技能需求表（项目ID、技能ID、需求水平）。

备注：技能水平分为初级、中级、高级，一个员工有多个技能。一个项目需要多个技能，一个项目也可以同一个技能需要多个水平。

---
### 问题 1

（10 分）员工技能表的主键、函数依赖是？满足第几范式？项目技能需求表主键、函数依赖是？满足第几范式？', '[]', '', '员工技能表主键：（员工 ID，技能 ID）。函数依赖：员工 ID，技能 ID）→技能水平。该表满足第三范式（3NF）。

项目技能需求表：主键是（项目 ID，技能 ID，需求水平）。函数依赖：（（项目 ID，技能 ID，需求水平）→ （项目 ID，技能 ID，需求水平）。该表满足第三范式（3NF）。

员工技能表分析

主键：员工技能表中包含员工 ID、技能 ID、技能水平三个字段。由于一个员工可以有多个技能，一个技能可以被多个员工拥有，所以单一的员工 ID 或技能 ID 都不能唯一标识一条记录，因此主键应该是（员工 ID，技能 ID）的组合。

函数依赖：在员工技能表中，技能水平完全依赖于主键（员工 ID，技能 ID），即给定一个员工 ID 和技能 ID 的组合，就能确定唯一的技能水平，可表示为 （员工 ID，技能 ID）→技能水平。

满足范式：该表满足第三范式（3NF）。因为所有非主属性（技能水平）完全依赖于主键，并且不存在非主属性对主属性的传递依赖。

项目技能需求表分析

主键：项目技能需求表包含项目 ID、技能 ID、需求水平三个字段。鉴于一个项目可以需要多个技能，一个技能也可以被多个项目需求，且一个项目对同一个技能可能有多个水平需求，所以单一的项目 ID 或技能 ID 不能唯一确定一条记录，主键是（项目 ID，技能 ID）的组合。

函数依赖：考虑到一个项目可以对应多个技能，并且同一个项目中一个技能也可以对应多个需求，主键（项目 ID，技能 ID，需求水平），可表示为 （项目 ID，技能 ID，需求水平）→ （项目 ID，技能 ID，需求水平）。

满足范式：该表满足第三范式（3NF）。所有非主属性（不存在非主属性）完全依赖于主键，也不存在非主属性对主属性的传递依赖。同时也满足 BCNF，因为找不到主属性对码的传递依赖。

这里你假如写都满足BCNF范式也可以。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-03-28 12:06:33', 0, 0);
