INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3152, 'question-system-analyst-2024-05-thesis-11829', '系统分析师', null, 2024, '2024年5月系统分析师论文-第4题', '论多源数据集成方法及其应用随着企业信息化程度的不断提高，企业中的数据也变得越来越分散和多样化。这些数据可能来自不同的应用系统、数据库、文件系统或外部数据源，如社交媒体、电子商务平台等。为了能够更好地利用这些数据，需要将它们整合到一个统一的数据存储系统中，以便于查询和分析，这个过程就是数据集成 (Data Integration)。
数据集成可以实现不同系统之间的自动化数据交换，从而简化业务流程，提高工作效率。通过整合不同数据源的数据，可以消除数据几余和不一致性，从而提高数据的质量和可靠性。统一的数据视图可以提供更全面和准确的信息，帮助企业和组织做出正确的决策。

请围绕"多源数据集成方法及其应用"论题，依次从以下三个方面进行论述
1.概要叙述你参与管理和开发的软件项目以及你在其中所承担的主要工作.
2.多源数据集成方法包含多种核心技术，请简要描述3种核心技术。
3.具体阐述你参与管理和开发的项目是如何应用多源数据集成方法进行设计与实现。', '[]', '', '写作要点： 一、简要叙述所参与管理和开发的安全攸关软件项目，并明确指出在其中承担的主要任务和开展的主要工作。 二、灾难恢复是指为了将信息系统从灾难造成的故障或瘫痪状态恢复到可正常运行状态，并将其支持的业务功能从灾难造成的不正常状态恢复到可接受状态而设计的活动和流程。灾难恢复措施在整个备份制度中占有相当重要的地位。因为它关系到系统在经历灾难后能否迅速恢复。 1. 灾难恢复的技术指标 灾难恢复的指标主要与容灾系统的数据恢复能力有关。灾难恢复的两个关键概念是恢复点目标(Recovery Point Objective，RPO)和恢复时间目标(Recovery Time Objective，RTO)。RPO是指灾难发生后，容灾系统能将数据恢复到灾难发生前时间点的数据，它是衡量企业在灾难发生后会丢失多少数据的指标；RTO则是指灾难发生后，从系统宕机导致业务停顿时刻开始，到系统恢复至可以支持业务部门运作，业务恢复运营之时，此两点之间的时间。RPO可简单描述为企业能容忍的最大数据丢失量，RTO可简单描述为企业能容忍的恢复时间。 理想状态下，希望RTO=0，RPO=0，即灾难发生对企业生产毫无影响，既不会导致生产停顿，也不会导致生产数据丢失。但显然这不现实，企业要做的是尽量减少灾难造成的损失。企业在构建容灾备份系统时，首先要找到对企业自身而言比较适合的RTO目标，即在该目标定义下，用于灾难备份的投入应不大于对应的业务损失。 2. 灾难恢复等级 在《信息系统灾难恢复规范》(GB/T20988-2007)中，将灾难恢复划分为6个等级。第1级为基本支持，第2级为备用场地支持，第3级为电子传输和部分设备支持，第4级为电子传输及完整设备支持，第5级为实时数据传输及完整设备支持，第6级为数据零丢失和远程集群支持。同时，该规范对灾难恢复能力等级评定原则和灾难备份中心的等级等也作了规范要求。 3. 容灾系统的分类 容灾系统的归类要由其最终达到的效果来决定，从其对系统的保护程度来分，可以将容灾系统分为数据容灾和应用容灾.它们的高可用性级别逐渐提高。 数据容灾的关注点在于数据，即灾难发生后可以确保用户原有的数据不会丢失或遭到破坏。 应用容灾是在数据容灾的基础上，再将执行应用处理能力复制一份，也就是说，在备份站点同样构建一套应用系统。应用容灾系统能提供不间断的应用服务，让用户应用的服务请求能够透明地继续运行，而感受不到灾难的发生，保证信息系统提供的服务完整、可靠和安全。 三、考生需结合自身参与项目的实际状况，论述该项目如何实施软件灾难恢复规划。答案需要涵盖灾难恢复需求的确定、灾难恢复策略的制定、灾难恢复策略的实现和灾难恢复预案的制定和管理等内容，并需要说明具体实施过程及实际效果。

写作要点： 一、简要叙述所参与管理和开发的安全攸关软件项目，并明确指出在其中承担的主要任务和开展的主要工作。 二、灾难恢复是指为了将信息系统从灾难造成的故障或瘫痪状态恢复到可正常运行状态，并将其支持的业务功能从灾难造成的不正常状态恢复到可接受状态而设计的活动和流程。灾难恢复措施在整个备份制度中占有相当重要的地位。因为它关系到系统在经历灾难后能否迅速恢复。 1. 灾难恢复的技术指标 灾难恢复的指标主要与容灾系统的数据恢复能力有关。灾难恢复的两个关键概念是恢复点目标(Recovery Point Objective，RPO)和恢复时间目标(Recovery Time Objective，RTO)。RPO是指灾难发生后，容灾系统能将数据恢复到灾难发生前时间点的数据，它是衡量企业在灾难发生后会丢失多少数据的指标；RTO则是指灾难发生后，从系统宕机导致业务停顿时刻开始，到系统恢复至可以支持业务部门运作，业务恢复运营之时，此两点之间的时间。RPO可简单描述为企业能容忍的最大数据丢失量，RTO可简单描述为企业能容忍的恢复时间。 理想状态下，希望RTO=0，RPO=0，即灾难发生对企业生产毫无影响，既不会导致生产停顿，也不会导致生产数据丢失。但显然这不现实，企业要做的是尽量减少灾难造成的损失。企业在构建容灾备份系统时，首先要找到对企业自身而言比较适合的RTO目标，即在该目标定义下，用于灾难备份的投入应不大于对应的业务损失。 2. 灾难恢复等级 在《信息系统灾难恢复规范》(GB/T20988-2007)中，将灾难恢复划分为6个等级。第1级为基本支持，第2级为备用场地支持，第3级为电子传输和部分设备支持，第4级为电子传输及完整设备支持，第5级为实时数据传输及完整设备支持，第6级为数据零丢失和远程集群支持。同时，该规范对灾难恢复能力等级评定原则和灾难备份中心的等级等也作了规范要求。 3. 容灾系统的分类 容灾系统的归类要由其最终达到的效果来决定，从其对系统的保护程度来分，可以将容灾系统分为数据容灾和应用容灾.它们的高可用性级别逐渐提高。 数据容灾的关注点在于数据，即灾难发生后可以确保用户原有的数据不会丢失或遭到破坏。 应用容灾是在数据容灾的基础上，再将执行应用处理能力复制一份，也就是说，在备份站点同样构建一套应用系统。应用容灾系统能提供不间断的应用服务，让用户应用的服务请求能够透明地继续运行，而感受不到灾难的发生，保证信息系统提供的服务完整、可靠和安全。 三、考生需结合自身参与项目的实际状况，论述该项目如何实施软件灾难恢复规划。答案需要涵盖灾难恢复需求的确定、灾难恢复策略的制定、灾难恢复策略的实现和灾难恢复预案的制定和管理等内容，并需要说明具体实施过程及实际效果。', 1, 2, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3153, 'question-system-analyst-2024-05-comprehensive-11994', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-网络体系结构与协议', '文件传输协议（FTP）是网络上两台计算机传送文件的协议，运行在 （ 问题1 ） 之上，是通过 Internet 将文件从一台计算机传输到另一台计算机的一种途径。', '[{"key":"A","text":"网络接口层","correct":false},{"key":"B","text":"IP","correct":false},{"key":"C","text":"UDP","correct":false},{"key":"D","text":"TCP","correct":true}]', 'D', '此题属于 TCP/IP协议族的常规考题，建议必须掌握。记住下图即可。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3154, 'question-system-analyst-2024-05-comprehensive-11995', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-磁盘冗余阵列', 'RAID技术中， （ 问题1 ） 是无独立校验盘的奇偶校验码磁盘阵列，非常适合于I/O需求频繁的应用，不太适合要求高数据传输率的应用。', '[{"key":"A","text":"RAID10","correct":false},{"key":"B","text":"RAID3","correct":false},{"key":"C","text":"RAID1","correct":false},{"key":"D","text":"RAID5","correct":true}]', 'D', '此题考察存储系统中 RAID 技术相关概念，是典型的记忆题，建议记一下，多次考到。第一问没什么好说，标准就是 8 个。后面考察的就是不同级别的特点。RAID 技术通过使用多个较小的磁盘驱动器替换单一的大容量磁盘驱动器，以及合理地在多个磁盘上分布存放数据来改善系统的I/O性能。RAID0具有高I/O性能和最高的磁盘空间利用率，但故障率高；RAID1具有最高的安全性，但磁盘空间利用率低；RAID2 采用海明码纠错技术，但不适用于小批量数据传输；RAID3和RAID4 采用奇偶校验码，适用于快速读取数据，但写入数据速度较慢；RAID5 采用无独立校验盘的奇偶校验码磁盘阵列，适合高I/O请求率的应用；RAID6具有两个独立的分布式校验方案，但价格昂贵；RAID7具有最优化的异步高I/O速率和高数据传输率；RAID10是高可靠性和高性能的组合。备份措施也是必要的。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3155, 'question-system-analyst-2024-05-comprehensive-11996', '系统分析师', '通信与网络安全技术', 2024, '2024年5月系统分析师综合知识-通信与网络安全技术', '以下有关 IPSec 协议的说法中， （ 问题1 ） 是不正确的。', '[{"key":"A","text":"IPSec在IP层提供安全服务","correct":false},{"key":"B","text":"IPSec是一种基于端对端的安全模式","correct":false},{"key":"C","text":"IPSec是一个工业标准网络安全协议","correct":false},{"key":"D","text":"IPSec仅针对 IPv4","correct":true}]', 'D', 'IPSec 协议出现在书本18 章，考察频率不高，建议了解即可 。 IPSec（Internet Protocol Security）是一个工业标准网络安全协议，旨在保护IP通信的安全性，防止窃听和篡改，同时抵御各种网络攻击。它通过加密和认证机制实现数据包的安全保障，支持IP层的所有流量，加密和/或认证数据，提高网络应用的安全性。IPSec适用于IPv4和IPv6，提供端到端的安全保护，通过密钥管理、密码保护服务和安全协议组来保障通信的私密性和完整性。它能够有效防范如数据包嗅探、数据篡改、身份欺骗、中间人攻击和拒绝服务攻击等安全威胁。', 1, 1, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3156, 'question-system-analyst-2024-05-comprehensive-11997', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-局域网与广域网', '不属于局域网的网络拓扑结构是 （ 问题1 ） 。', '[{"key":"A","text":"点对点结构","correct":true},{"key":"B","text":"星型结构","correct":false},{"key":"C","text":"总线型结构","correct":false},{"key":"D","text":"环型结构","correct":false}]', 'A', '此题出自书本第四章计算机网络，属于概念辨析类题目，建议记忆。构成局域网的网络拓扑结构主要有星型结构、总线结构、环型结构和网状结构。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3157, 'question-system-analyst-2024-05-comprehensive-11998', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-网络工程', '信道容量是指在信道上进行无差错传输的最大传输速率。若一个信道带宽为2MHz，信噪比为30dB，则信道容量C约为 （ 问题1 ） 。', '[{"key":"A","text":"100Mbps","correct":false},{"key":"B","text":"50Mbps","correct":false},{"key":"C","text":"20Mbps","correct":true},{"key":"D","text":"10Mbps","correct":false}]', 'C', '此题出自书本第四章计算机网络相关内容，建议掌握。有噪声干扰的实际信道。使用香农理论进行计算，香农理论描述了有限带宽、有随机热噪声信道的最大传输速率与信道带宽、信号噪声功率比（S/N，简称为信噪比）之间的关系。但是书上描述有误。这里给出正确解法。

首先给出分贝计算公式

其中 S 是信号功率，N 是噪声功率。再给出香农公式。

其中，C 是最大信息传输速率（单位：比特每秒），B 是信道带宽（单位：赫兹），S 是信号功率，N 是噪声功率。

此题告诉了我们 30dB 我们可以反推出 S/N 之比是 1000。代入香农公式得到 C = 2M * 10 = 20Mbps。', 1, 2, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3158, 'question-system-analyst-2024-05-comprehensive-11999', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-进程管理', '产生死锁的必要条件不包括 （ 问题1 ） 。', '[{"key":"A","text":"不可剥夺条件","correct":false},{"key":"B","text":"共享条件","correct":true},{"key":"C","text":"环路条件","correct":false},{"key":"D","text":"互斥条件","correct":false}]', 'B', '此题考察进程管理的相关内容，属于书本第三章的知识点，建议必须掌握。( 1 ) 互斥条件。任一时刻只允许一个进程使用资源。( 2 ) 不剥夺条件。进程已经占用的资源，不会被强制剥夺。( 3 ) 请求与保持条件。进程在请求其余资源时，不主动释放已经占有的资源。( 4 ) 环路条件。环路中每一条边是进程在请求另一个进程己经占有的资源。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3159, 'question-system-analyst-2024-05-comprehensive-12000', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-内存管理', '如果页面的访问顺序为（0，0，1，1，3，1，2） ，有2个页帧可供程序使用，按照先进先出页面置换算法，共产生 （ 问题1 ） 缺页中断。', '[{"key":"A","text":"2 次","correct":false},{"key":"B","text":"3 次","correct":false},{"key":"C","text":"4 次","correct":true},{"key":"D","text":"5 次","correct":false}]', 'C', '此题考察页面置换算法的相关信息，建议必须掌握。所谓缺指的是当软件试图访问已映射在虚拟地址空间中，但并未被加载在物理内存中的一个分页时，由中央处理器的内存管理单元所发出的中断。这里一开始假设内存里没有0,1,2,3页帧。所以程序要第一次访问 0 号，1 号页面的时候各产生一次缺页中断（总计 2 次）。当访问到 3 号页面的时候再次出现缺页中断（总计 3次），并且根据先进先出算法把 0 号页面替换出去，之后访问 1 号页面，发现 1 号页面在物理内存中，不产生置换。最后访问 2 号页面，发现不在内存中，产生缺页中断（总计 4 次），并且根据先进先出算法把 1 号页面替换出去.最后物理内存种剩下 3 号页面和 2 号页面。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3160, 'question-system-analyst-2024-05-comprehensive-12001', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-内存管理', '源程序编译后链接到的地址称为 （ 问题1 ） 。', '[{"key":"A","text":"逻辑地址","correct":true},{"key":"B","text":"绝对地址","correct":false},{"key":"C","text":"物理地址","correct":false},{"key":"D","text":"实际地址","correct":false}]', 'A', '此题考察操作系统内存管理相关的知识点，属于超纲内容，建议了解即可。源程序编译后链接到一个以0地址为始地址的线性或多维虚拟地址空间。 而且每个进程都拥有这样一个空间，每个指令和数据都在这个虚拟地址空间拥有确定的地址，把这个地址称为虚拟地址或者虚拟地址。 把进程装入到内存是时会把逻辑地址转换成物理地址。', 1, 1, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3161, 'question-system-analyst-2024-05-comprehensive-12002', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-进程管理', '在单处理机系统中，某个时刻只能有一个进程处于 （ 问题1 ） 。', '[{"key":"A","text":"阻塞状态","correct":false},{"key":"B","text":"睡眠状态","correct":false},{"key":"C","text":"运行状态","correct":true},{"key":"D","text":"就绪状态","correct":false}]', 'C', '此题考察操作系统进程管理的相关概念，比较简单，建议必须掌握。因为此题说是单机处理机系统，只有 1 个 CPU，所以只能处理一个进程，即某个时刻只能有一个进程处于运行状态。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3162, 'question-system-analyst-2024-05-comprehensive-12003', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-文件系统', 'Windows 和 UNIX 系统通常采用 （ 问题1 ） 目录结构对文件进行组织和管理。', '[{"key":"A","text":"一级","correct":false},{"key":"B","text":"二级","correct":false},{"key":"C","text":"顺序","correct":false},{"key":"D","text":"多级树形","correct":true}]', 'D', '此题考察操作系统中文件系统的相关概念，难度不大，建议必须掌握。Windows 和 UNIX 系统通常采用树状目录结构对文件进行组织和管理。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3163, 'question-system-analyst-2024-05-comprehensive-12004', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-进程管理', '（ 问题1 ） 依赖于操作系统内核，由内核的内部需求进行创建和撤销。', '[{"key":"A","text":"用户线程","correct":false},{"key":"B","text":"内核线程","correct":true},{"key":"C","text":"应用线程","correct":false},{"key":"D","text":"轻权线程","correct":false}]', 'B', '此题考察操作系统种线程管理的相关内容。难度不是很大，建议必须掌握。线程分类为内核级线程和用户线程。内核级线程是由操作系统内核管理和调度的线程。每个内核级线程都有内核线程控制块，由操作系统内核负责管理。用户级线程是由用户空间的线程库管理和调度的线程。线程的管理完全在用户空间进行，内核对用户级线程一无所知。轻权线程是计算机科学中线程的一种，它相比于传统的线程（重权线程）具有较低的创建和管理开销。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3164, 'question-system-analyst-2024-05-comprehensive-12005', '系统分析师', '性能指标', 2024, '2024年5月系统分析师综合知识-性能指标', '（ 问题1 ） 是指在给定的时间内，系统所能处理（输入、加工、输出）的任务数量。', '[{"key":"A","text":"吞吐量","correct":true},{"key":"B","text":"峰值","correct":false},{"key":"C","text":"并发数","correct":false},{"key":"D","text":"生产率","correct":false}]', 'A', '此题考察性能指标的相关概念，属于常规考题，建议必须掌握。吞吐量指的是一个系统在一定时间内处理的工作量，通常以单位时间内完成的任务或处理的数据量来衡量。峰值是指系统在特定时间段内达到的最高性能水平。并发数指的是在同一时间内，系统能够同时处理的任务或请求的数量。生产率通常用于衡量在特定时间内完成的有效工作量，这个比较容易和吞吐量搞混。它不仅考虑到处理的任务或数据量，还关注执行这些任务的效率。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3165, 'question-system-analyst-2024-05-comprehensive-12006', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-指令系统', '寄存器间接寻址方式中，操作数被存放在 （ 问题1 ） 。', '[{"key":"A","text":"主存单元","correct":true},{"key":"B","text":"程序计数器","correct":false},{"key":"C","text":"通用寄存器","correct":false},{"key":"D","text":"外部存储单元","correct":false}]', 'A', '此题不在书本的范围之内，可能是未来新教材铺垫的知识点，建议记忆一下。常见指令寻址方式包括立即寻址（操作数在指令中，执行快但受指令长度限制）、直接寻址（指令中地址即操作数地址，简单但地址空间有限）、间接寻址（地址指向存操作数地址的单元，可访大空间但需两次内存访问）、寄存器寻址（操作数在寄存器，极快但数量有限）、寄存器间接寻址（寄存器含操作数地址指向内存，可灵活访问但需额外内存访问）。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3166, 'question-system-analyst-2024-05-comprehensive-12007', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-计算机系统层次结构', '计算机系统组成中， （ 问题1 ） 负责将程序指令从主存取到 CPU 进行执行。', '[{"key":"A","text":"控制器","correct":true},{"key":"B","text":"高速缓存","correct":false},{"key":"C","text":"算数逻辑单元","correct":false},{"key":"D","text":"数据通路","correct":false}]', 'A', '此题主要考察 CPU 相关组成结构，出自书本第六章，属于比较深入的考察，建议必须掌握。控制器是 CPU 的“大脑”，有指令获取、解码、控制信号生成、顺序控制、中断处理等功能；运算器是 CPU 的“手”，负责算术、逻辑、移位、条件判断等运算；控制器和运算器协同工作，通过获取、解码、执行、结果存储的流程及循环执行来执行指令，中断时控制器暂停任务处理中断，之后恢复。此题问你取指令的相关操作（负责将程序指令从主存取到 CPU 进行执行）属于控制器的工作。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3167, 'question-system-analyst-2024-05-comprehensive-12008', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-存储器系统', '（ 问题1 ） 是一种基于行业标准的串行硬件驱动器接口，该接口需要硬件芯片的支持，优势是支持热插拔、传输速度快、执行效率高。', '[{"key":"A","text":"SATA","correct":true},{"key":"B","text":"RS-232","correct":false},{"key":"C","text":"IDE","correct":false},{"key":"D","text":"ATA","correct":false}]', 'A', '此题主要考察计算机组成原理中接口的相关概念，出自书本第六章接口那一小节，建议了解即可。（1）IDE是常用的磁盘接口，分为普通IDE和增强型IDE（EIDE）。普通IDE数据传输率不超过1.5Mbps，数据宽度为8位，最多连接4个设备，每个硬盘容量不超过528MB。EIDE传输率达150Mbps，数据宽度为32位。（2）ATA是全球硬盘标准，包括IDE/EIDE。ATA经历多次升级，保持向后兼容性。最后一个版本ATA-7（Ultra DMA 133）支持1064Mbps（133MBps）传输速率。（3）SATA是基于行业标准的串行接口，传输速率从初始的1200Mbps（150MBps）到后续版本的3000Mbps，并有望达4800Mbps。SATA支持热插拔，传输速度快，效率高。（4）eSATA是扩展的SATA接口，用于连接外部设备，支持3.2Gbps传输速率，物理连接稳固，支持数千次插拔。（5）SCSI用于大容量存储设备，音频设备和CD-ROM驱动器。支持多个设备菊花链连接，最大同步传输速率为5Gbps（640MBps），设备间可独立交换数据。（6）PCMCIA用于笔记本电脑的接口标准，现称为PC Card接口。支持3.3V/5V，具有电源管理服务，32位总线接口，用于内存扩展、传真和调制解调器功能。（7）又称i.Link或FireWire，初始传输速率为200Mbps，现在的FireWire 800速率为800Mbps，1394b（FireWire 3200）支持3200Mbps。支持热插拔和不同速率设备，常用于数码相机、摄像机等。（8）USB接口为串行总线接口，允许设备以雏菊链形式接入，最多连接127个设备，支持热插拔。USB 1.0速度为12Mbps，USB 2.0为480Mbps，USB 3.0为4.8Gbps。', 1, 1, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3168, 'question-system-analyst-2024-05-comprehensive-12009', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-输入输出系统', '总线是一组能为多个部件分时共享的公共信息传送线路。如按总线功能来划分，则不包含 （ 问题1 ） 总线。', '[{"key":"A","text":"控制","correct":false},{"key":"B","text":"地址","correct":false},{"key":"C","text":"服务","correct":true},{"key":"D","text":"数据","correct":false}]', 'C', '此题考察总线的划分，出自书本第六章的相关知识点，建议学有余力的同学进行记忆。按总线功能可分为地址总线、数据总线、控制总线；按在微机系统中的位置可分为机内总线和机外总线；按功用来分主要有局部总线、系统总线、通信总线；按总线中数据线多少可分为并行总线和串行总线，并行总线数据传输速率高但不宜过长，串行总线适合远距离通信但数据传输速率较低，且多数系统总线为并行总线，多数通信总线为串行总线。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3169, 'question-system-analyst-2024-05-comprehensive-12010', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-计算机系统层次结构', '数据通路的功能是实现 CPU 内部的运算器和寄存器，以及寄存器之间的 （ 问题1 ） 。', '[{"key":"A","text":"数据交换","correct":true},{"key":"B","text":"控制信号交换","correct":false},{"key":"C","text":"数据存储","correct":false},{"key":"D","text":"控制信号存储","correct":false}]', 'A', '此题考察数据通路的相关概念，书本上没有详细展开，这里做个简单说明。数据通路的功能是实现 CPU 内部运算器和寄存器之间，以及寄存器之间的数据传输和交换。它主要负责（1）数据传输。在运算器与寄存器之间传输数据。例如，从寄存器中读取数据到运算器进行运算，或者将运算结果写回到寄存器中。（2）数据交换。在寄存器之间直接进行数据交换，而不通过运算器。这样可以提高数据处理的效率。（3）控制信号传递。传递控制信号以协调不同部件的工作，使得数据能够正确地传输和交换。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3170, 'question-system-analyst-2024-05-comprehensive-12011', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-指令系统', '以下有关RISC的说法中， （ 问题1 ） 是不正确的。', '[{"key":"A","text":"指令数量少","correct":false},{"key":"B","text":"指令的寻址方式少","correct":false},{"key":"C","text":"指令简单","correct":false},{"key":"D","text":"指令长度不固定","correct":true}]', 'D', '此题考察指令系统相关知识，出自书本6.4 章节，建议必须掌握。RISC的特点是指令数量少，使用频率接近，定长格式，大部分为单周期指令，操作寄存器，只有Load/Store操作内存；寻址方式少；并增加了通用寄存器；硬布线逻辑控制为主；适合采用流水线。CISC的特点是指令数量多，使用频率差别大，可变长格式；寻址方式多；常常采用微程序控制技术（微码）；且研制周期长。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3171, 'question-system-analyst-2024-05-comprehensive-12012', '系统分析师', '企业信息化', 2024, '2024年5月系统分析师综合知识-信息系统战略规划方法', '在企业战略与信息化战略集成中， （ 问题1 ） 是一种以业务为导向的、全面的IT管理咨询实施方法论。', '[{"key":"A","text":"业务与IT整合","correct":true},{"key":"B","text":"业务架构","correct":false},{"key":"C","text":"业务与IT架构","correct":false},{"key":"D","text":"企业IT架构","correct":false}]', 'A', '此题考察信息化战略的相关概念，书本原话，属于高频考点，建议必须记忆。信息化战略从企业战略出发，服务于企业战略，同时又影响和促进企业战略。企业战略与信息化战略集成的主要方法有 BITA（业务与IT整合）和 EITA（企业IT架构）。

（1）业务与IT整合。BITA是一种以业务为导向的、全面的IT管理咨询实施方法论。从制订企业战略、建立（或改进）企业组织结构和业务流程，到进行IT管理和制订过渡计划，使IT能够更好地为企业战略和目标服务。BITA 适用于信息系统不能满足当前管理中的业务需要，业务和 IT 之间总是有不一致的地方。BITA 的主要步骤是评估和分析企业当前业务和 IT 不一致的领域，整理出企业的业务远景和未来战略，建立业务模型，提出达到未来目标的转变过程建议和初步计划，以及执行计划。

（2）企业IT架构。EITA 分析企业战略，帮助企业制订 IT 战略，并对其投资决策进行指导。在技术、信息系统、信息、IT 组织和IT流程方面，帮助企业建立IT的原则规范、模式和标准，指出IT需要改进的方面并帮助制订行动计划。EITA 适用于现有信息系统和IT基础架构不一致、不兼容和缺乏统一的整体管理的企业。这里的关键词在于业务所以选 A。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3172, 'question-system-analyst-2024-05-comprehensive-12013', '系统分析师', '结构化设计', 2024, '2024年5月系统分析师综合知识-结构化设计', '内聚用来度量一个模块内部各个元素彼此结合的紧密程度，内聚程度最高的是 （ 问题1 ） 。', '[{"key":"A","text":"功能内聚","correct":true},{"key":"B","text":"通信内聚","correct":false},{"key":"C","text":"时间内聚","correct":false},{"key":"D","text":"逻辑内聚","correct":false}]', 'A', '此题考察系统设计结构化设计相关内容，出自书本第 13 章，建议必须掌握。内聚表示模块内部各成分之间的联系程度，是从功能角度来度量模块内的联系，一个好的内聚模块应当恰好做目标单一的一件事情。模块的内聚类型通常也可以分为7种，根据内聚度从高到低的排序如表所示 （特别注意功能内聚和偶然内聚）。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3173, 'question-system-analyst-2024-05-comprehensive-12014', '系统分析师', '信息系统开发方法', 2024, '2024年5月系统分析师综合知识-信息系统开发方法', '服务建模可以分为服务发现、服务规约和服务实现三个阶段。在服务发现阶段， （ 问题1 ） 是从业务着手进行分析，将业务进行领域分解、流程分解和变化分析。', '[{"key":"A","text":"中间对齐的方式","correct":false},{"key":"B","text":"业务目标建模","correct":false},{"key":"C","text":"自上而下的方式","correct":true},{"key":"D","text":"资产分析","correct":false}]', 'C', '此题考察面向服务中服务建模的相关知识点，出自书本第七章，建议了解即可。服务建模分为服务发现、服务规约和服务实现三个阶段。服务发现有自上而下（业务领域分解、流程分解、变化分析）、自下而上（已有资产分析）、中间对齐（业务目标建模）三种方式来得到候选服务；服务规约是对候选服务分类，决定是否暴露，还要考虑信息系统特性，包括服务编排等过程；服务实现是将服务分配到相应构件中并确定实现方式，且无论哪种方式都需进行技术可行性分析。', 1, 1, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3174, 'question-system-analyst-2024-05-comprehensive-12015', '系统分析师', '新技术应用', 2024, '2024年5月系统分析师综合知识-新技术应用', 'Web3.0以 （ 问题1 ） 为基础构筑信任科技体系，打造价值互联网信任根基。', '[{"key":"A","text":"人工智能","correct":false},{"key":"B","text":"隐私计算","correct":false},{"key":"C","text":"区块链","correct":true},{"key":"D","text":"数据治理","correct":false}]', 'C', '此题考察 Web3.0的相关应用，估计新教材会提到相关内容，建议了解即可。Web 3.0 相关技术包括区块链（分布式账本确保数据透明不可篡改）、智能合约（基于区块链自动执行协议）、分布式存储（如 IPFS 等提高安全性可靠性）、去中心化身份（DID 让用户创建管理数字身份）、语义网（使机器理解处理数据关系含义）、零知识证明（保护隐私数据安全）、去中心化应用（DApps 基于区块链智能合约运行）、去中心化自治组织（DAO 通过智能合约管理，成员投票治理）、边缘计算（提高响应速度和效率）。', 1, 1, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3175, 'question-system-analyst-2024-05-comprehensive-12016', '系统分析师', '信息安全', 2024, '2024年5月系统分析师综合知识-系统安全与保密', '密钥管理处理密钥自产生到销毁整个过程中的问题。其中， （ 问题1 ） 是适用于封闭网，以传统的密钥管理中心为代表的机制。', '[{"key":"A","text":"PKI","correct":false},{"key":"B","text":"KMI","correct":true},{"key":"C","text":"LPK","correct":false},{"key":"D","text":"CPK","correct":false}]', 'B', '此题考察三种密钥管理体制，出自书本18 章，建议必须了解。密钥是加密算法中关键的可变部分，信息系统的安全性依赖于密钥的保护而非算法或硬件。密码机制可以公开，密码设备可能丢失，但同型号的设备仍可使用。主要的密钥管理体制有三种：KMI (Key Management Infrastructure)。适用于封闭网，通过密钥分配中心（KDC）发放密钥，有静态分发和动态分发两种方式。PKI (Public Key Infrastructure)。适用于开放网，通过CA和数字证书库等系统进行密钥和证书管理，解决了依赖秘密信道的问题。SPK (Seeded Public Key)。适用于规模化专用网，有多重公钥和组合公钥两种实现方法，提供了一种理想的密钥管理解决方案。此题提到了封闭网，所以选择 KMI。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3176, 'question-system-analyst-2024-05-comprehensive-12017', '系统分析师', '数学建模', 2024, '2024年5月系统分析师综合知识-数学建模', '三位专家给10幅画作投票，每位专家有5票可以投给其中的5幅画作。凡是大于等于3票的画作评为A等，得2票的画作评为B等，得1票的画作评为C等。投票结果，每幅画作都有得票。据此，以下叙述中只有 （ 问题1 ） 是正确的。', '[{"key":"A","text":"A等最多可有5幅","correct":false},{"key":"B","text":"A等比C等少5幅","correct":true},{"key":"C","text":"B等与C等共7幅","correct":false},{"key":"D","text":"A等与B等共6幅","correct":false}]', 'B', '此题考察基本的分析能力，建议需要尝试做一下。因为 10 幅画都有投票，所以至少消耗 10 张票。三个专家每个人 5 张票合计 15 张票。那么还有 5 张票可以用。

（1）5 张票全部用于凑 A 等，最多只能凑 5/2 = 2 张A等，此时 C等最多为 7，还有1幅 B。所以 A 错。（2）由 1 可知，C,D 都是错的，所以选 B。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3177, 'question-system-analyst-2024-05-comprehensive-12018', '系统分析师', '数学与工程', 2024, '2024年5月系统分析师综合知识-网络与最大流量', '从油田S到大城市T经过五个中转站A、B、C、D、E的输油管道网络如下图。图中每段管道旁的数字注明了该段管道的输油能力（每天输油万吨数）。根据该图，从S到T的总输油能力为 （ 问题1 ） 万吨/天。', '[{"key":"A","text":"17","correct":false},{"key":"B","text":"18","correct":false},{"key":"C","text":"19","correct":true},{"key":"D","text":"20","correct":false}]', 'C', '此题考察最大流量的相关问题，属于基础题。建议必须掌握。

首先断开 SADT，再断开 SACDT，再断开 SBET，再断开 SBCET。当然你可以选取其他方法（注意这种贪心算法是有缺陷的，对于此题这里的其他方法可能得不到最大流 19，但是这种方法比较容易简单，否则要用标号法正推逆推复杂度加倍，在真实的考试中，假如一种路径没有答案，多试几种路径选择方法）。最后把流量累加 5+5+5+4 = 19。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3178, 'question-system-analyst-2024-05-comprehensive-12019', '系统分析师', '数据库系统', 2024, '2024年5月系统分析师综合知识-数据库理论', '（ 问题1 ） 是指一个事务的执行不能被其他事务干扰，即使有多个事务并行执行，但看上去每个事务按串行调度执行一样。', '[{"key":"A","text":"一致性","correct":false},{"key":"B","text":"隔离性","correct":true},{"key":"C","text":"持久性","correct":false},{"key":"D","text":"原子性","correct":false}]', 'B', '本题考查数据库事务特性的相关概念，出自书本第五章，属于基本知识点，建议必须掌握。原子性指事务操作要么全成功要么全失败回滚；一致性指事务使数据库在前后都保持一致性状态；隔离性指一个事务执行不受其他事务干扰；持久性指事务提交后对数据库数据改变永久，不受故障影响。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3179, 'question-system-analyst-2024-05-comprehensive-12020', '系统分析师', '数据库理论', 2024, '2024年5月系统分析师综合知识-数据库理论', '在以下元组演算公式中，与P1vP2等价的是 （ 问题1 ） 。', '[{"key":"A","text":"﹁（﹁P1v﹁P2）","correct":false},{"key":"B","text":"﹁P1v﹁P2","correct":false},{"key":"C","text":"﹁（﹁P1∧﹁P2）","correct":true},{"key":"D","text":"﹁P1∧﹁P2","correct":false}]', 'C', '本题考察关系元组演算相关内容属于常规知识点，建议必须掌握。首先﹁表示取补集，∧表示交集，v表示并集。这里用图示法比较容易。做出两个相交的圆，然后计算出两个圆的补集，然后做交集再取反就是答案。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3180, 'question-system-analyst-2024-05-comprehensive-12021', '系统分析师', '数据库', 2024, '2024年5月系统分析师综合知识-数据库SQL', '从关系 R 中抽取出满足给定限制条件记录的操作称为 （ 问题1 ） 。', '[{"key":"A","text":"选择","correct":true},{"key":"B","text":"连接","correct":false},{"key":"C","text":"除","correct":false},{"key":"D","text":"投影","correct":false}]', 'A', '此题考察关系代数基本操作的相关概念，属于常规高频考点，建议必须掌握。（1）选择。从关系中根据指定的条件筛选出满足条件的元组，相当于对关系进行过滤。（2）连接。将两个或多个关系根据特定的关联条件组合在一起，产生一个新的关系，包含了相关联的元组信息。常见的有内连接、外连接（左外连接、右外连接、全外连接）等不同类型。（3）除。在R和S的联系 RS中，找出与S中所有的元组有关系的R元组。（4）投影。从关系中选取若干属性列组成新的关系，它会去除不需要的属性列，只保留指定的那些列的信息。除法比较难理解，举个例子说明。RS÷S 在这里解决的问题就是“得到选修了所有课程的学生”', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3181, 'question-system-analyst-2024-05-comprehensive-12022', '系统分析师', '数据库模式', 2024, '2024年5月系统分析师综合知识-数据库模式', '数据分片将数据库整体逻辑结构分解为合适的逻辑片段，下列选项中， （ 问题1 ） 不属于数据分片的原则。', '[{"key":"A","text":"相交性","correct":true},{"key":"B","text":"不相交性","correct":false},{"key":"C","text":"重构性","correct":false},{"key":"D","text":"完整性","correct":false}]', 'A', '此题考察数据分片原则，属于必须知道的内容，建议必须掌握。不管采用哪种分片方式，数据分片都应遵循如下原则：

（1）完整性。全局关系的所有数据都必须分配到各个片段中，不允许某些数据属于全局关系但不属于任何片段。（2）重构性。各个片段可以重构原来的全局关系。（3）不相交性。全局关系中的每个元组仅属于一个片段，不能在多个片段中重复出现。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3182, 'question-system-analyst-2024-05-comprehensive-12023', '系统分析师', '信息安全', 2024, '2024年5月系统分析师综合知识-系统安全与保密', '对称加密算法中， （ 问题1 ） 的明文和密文都是64位，密钥长度为128位。', '[{"key":"A","text":"IDEA","correct":true},{"key":"B","text":"3DES","correct":false},{"key":"C","text":"DES","correct":false},{"key":"D","text":"RSA","correct":false}]', 'A', '此题对对称加密的内容考察的更加深刻了，属于书本18 章的内容，建议必须掌握。（1）对称加密算法是私钥加密算法，加密与解密密钥相同或可推导，分分组密码和序列密码，常见有 IDEA（明文密文 64 位、密钥 128 位，在 DES 基础上发展）、DES（明文密文 64 位、56 位密钥加 8 位奇偶校验位，有穷举法攻击，出现 3DES 用 112 位密钥三次加密）；（2）非对称加密算法为公钥加密算法，公钥私钥不同且不可推导，可适应开放环境，能实现数字签名与验证，常见的 RSA 以发明者命名，密钥长度 512 位，保密性取决于数分解难度，计算量大破解难，但加密/解密速度慢，主要用于数字签名。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3183, 'question-system-analyst-2024-05-comprehensive-12024', '系统分析师', '法律法规', 2024, '2024年5月系统分析师综合知识-知识产权与专利', '我国发明专利从申请日期开始保护期为 （ 问题1 ） 年。', '[{"key":"A","text":"5","correct":false},{"key":"B","text":"10","correct":false},{"key":"C","text":"15","correct":false},{"key":"D","text":"20","correct":true}]', 'D', '此题考察专利法的相关知识，虽然书本上没有，但是近年来持续考察，建议必须掌握。我国《专利法》第四十二条规定：“发明专利权的期限为20年，实用新型专利权的期限为10年，外观设计专利权的期限为15年（2022 年起，外观设计专利权期限由10年延长为15年），均自申请日起计算。”', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3184, 'question-system-analyst-2024-05-comprehensive-12025', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-网络体系结构与协议', 'SSL 属于 TCP/IP 网络协议层中的 （ 问题1 ） 。 SSL 包含的主要子协议是记录协议、 （ 问题2 ） 。', '[{"key":"A","text":"应用层","correct":false},{"key":"B","text":"传输层","correct":true},{"key":"C","text":"网络层","correct":false},{"key":"D","text":"数据链路层","correct":false}]', 'B', '此题考察 SSL 协议的相关知识，出自书本 18 章，建议必须掌握。TCP/IP协议分为四个层次应用层、传输层、网络层和数据链路层（有时也称为网络接口层）。SSL 属于 TCP/IP 网络协议层中的传输层安全协议，用于在 Internet 上传送机密文件。SSL 协议由捤手协议、记录协议和警报协议组。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3185, 'question-system-analyst-2024-05-comprehensive-12026', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-网络体系结构与协议', 'SSL 属于 TCP/IP 网络协议层中的 （ 问题1 ） 。 SSL 包含的主要子协议是记录协议、 （ 问题2 ） 。', '[{"key":"A","text":"AH协议和ESP协议","correct":false},{"key":"B","text":"AH协议和握手协议","correct":false},{"key":"C","text":"警告协议和ESP","correct":false},{"key":"D","text":"警告协议和握手协议","correct":true}]', 'D', '此题考察 SSL 协议的相关知识，出自书本 18 章，建议必须掌握。TCP/IP协议分为四个层次应用层、传输层、网络层和数据链路层（有时也称为网络接口层）。SSL 属于 TCP/IP 网络协议层中的传输层安全协议，用于在 Internet 上传送机密文件。SSL 协议由捤手协议、记录协议和警报协议组。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3186, 'question-system-analyst-2024-05-comprehensive-12027', '系统分析师', '企业信息化', 2024, '2024年5月系统分析师综合知识-企业信息系统', '以下哪项不是 ERP 系统的基本组成部分 （ 问题1 ） 。', '[{"key":"A","text":"物流管理","correct":false},{"key":"B","text":"企业外部管理","correct":true},{"key":"C","text":"生产计划","correct":false},{"key":"D","text":"财务管理","correct":false}]', 'B', '此题考察 ERP 系统相关的内容，出自书本第七章，建议必须掌握。ERP 为企业提供多层面、全方位的功能，企业一般管理包括生产控制、物流管理和财务管理，这三大系统相互集成，且人力资源管理也被越来越多的 ERP 供应商纳入系统。典型的 ERP 系统主要功能模块有：财会管理（含会计核算和财务管理模块）、物流管理（含分销管理、库存控制和采购管理模块）、生产控制管理（含主生产计划、物料需求计划等模块）、人力资源管理（含人力资源规划辅助决策、招聘管理等模块）。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3187, 'question-system-analyst-2024-05-comprehensive-12028', '系统分析师', '开发模型', 2024, '2024年5月系统分析师综合知识-开发模型', '（ 问题1 ） 强调风险分析，比较适用于庞大、复杂且高风险的系统。', '[{"key":"A","text":"瀑布模型","correct":false},{"key":"B","text":"螺旋模型","correct":true},{"key":"C","text":"V模型","correct":false},{"key":"D","text":"原型化模型","correct":false}]', 'B', '此题考察软件开发模型的相关内容，属于重点内容，建议必须掌握。瀑布模型是一种传统的软件开发模型，按照线性顺序依次进行需求分析、设计、编码、测试和维护等阶段，各阶段之间具有严格的顺序性和依赖性。螺旋模型将瀑布模型和快速原型模型结合起来，强调风险分析，通过多次迭代逐步完善软件产品。V 模型是一种软件开发过程中的测试模型，将软件开发过程中的各个阶段与相应的测试阶段对应起来。原型模型通过快速构建原型来获取用户需求和反馈，然后不断改进和完善原型，最终得到满足用户需求的产品。这里提到风险分析，显然是螺旋模型。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3188, 'question-system-analyst-2024-05-comprehensive-12029', '系统分析师', '系统安全与保密', 2024, '2024年5月系统分析师综合知识-系统安全与保密', '数字签名使用了 （ 问题1 ） 这两种技术。', '[{"key":"A","text":"非对称加密和摘要","correct":true},{"key":"B","text":"对称加密和摘要","correct":false},{"key":"C","text":"非对称加密和置换加密","correct":false},{"key":"D","text":"对称加密和置换加密","correct":false}]', 'A', '此题考察数字签名的相关内容，出自书本18 章，但是更细，建议必须掌握。数字签名先对数据进行摘要计算，然后使用私钥对摘要进行非对称加密，形成数字签名，接收方再用公钥验证签名解密获得摘要，再对明文做摘要进行对比从而确认数据的来源、完整性等。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3189, 'question-system-analyst-2024-05-comprehensive-12030', '系统分析师', '面向对象分析方法', 2024, '2024年5月系统分析师综合知识-面向对象分析方法', '在UML中，对象行为是通过交互来实现的，是对象间完成某一目的而进行的一系列消息交换。消息序列可用两种图来表示，强调消息时间次序的图称为 （ 问题1 ） ，表示对象协作的是 （ 问题2 ） 。', '[{"key":"A","text":"协作图","correct":false},{"key":"B","text":"序列图（顺序图）","correct":true},{"key":"C","text":"活动图","correct":false},{"key":"D","text":"状态图","correct":false}]', 'B', '此题考察 UML 14 种图的基本辨析，属于常规高频考点，建议必须掌握。总结如下表所示。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3190, 'question-system-analyst-2024-05-comprehensive-12031', '系统分析师', '面向对象分析方法', 2024, '2024年5月系统分析师综合知识-面向对象分析方法', '在UML中，对象行为是通过交互来实现的，是对象间完成某一目的而进行的一系列消息交换。消息序列可用两种图来表示，强调消息时间次序的图称为 （ 问题1 ） ，表示对象协作的是 （ 问题2 ） 。', '[{"key":"A","text":"协作图","correct":true},{"key":"B","text":"序列图（顺序图）","correct":false},{"key":"C","text":"活动图","correct":false},{"key":"D","text":"状态图","correct":false}]', 'A', '此题考察 UML 14 种图的基本辨析，属于常规高频考点，建议必须掌握。总结如下表所示。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3191, 'question-system-analyst-2024-05-comprehensive-12032', '系统分析师', '开发模型', 2024, '2024年5月系统分析师综合知识-开发模型', '与用户沟通最多的是以下那种开发方法 （ 问题1 ） 。', '[{"key":"A","text":"敏捷开发方法","correct":true},{"key":"B","text":"RUP","correct":false},{"key":"C","text":"原型方法","correct":false},{"key":"D","text":"螺旋模型","correct":false}]', 'A', '此题考察软件开发模型的相关内容，属于重点内容，建议必须掌握。瀑布模型是一种传统的软件开发模型，按照线性顺序依次进行需求分析、设计、编码、测试和维护等阶段，各阶段之间具有严格的顺序性和依赖性。螺旋模型将瀑布模型和快速原型模型结合起来，强调风险分析，通过多次迭代逐步完善软件产品。V 模型是一种软件开发过程中的测试模型，将软件开发过程中的各个阶段与相应的测试阶段对应起来。原型模型通过快速构建原型来获取用户需求和反馈，然后不断改进和完善原型，最终得到满足用户需求的产品。敏捷模型强调适应变化与快速响应客户需求，其核心原则为个体和互动比流程和工具重要，工作的软件比详尽文档重要，客户合作比合同谈判重要，响应变化比遵循计划重要。所以此题选敏捷模型。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3192, 'question-system-analyst-2024-05-comprehensive-12033', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-输入输出系统', '按照存储虚拟化实现的层面来分，以下不属于存储虚拟化的是 （ 问题1 ） 。', '[{"key":"A","text":"基于存储设备的虚拟化","correct":false},{"key":"B","text":"基于存储网络的虚拟化","correct":false},{"key":"C","text":"基于操作系统的虚拟化","correct":true},{"key":"D","text":"基于主机的虛拟化","correct":false}]', 'C', '此题考察存储虚拟化的相关概念，出自书本第六章，建议必须掌握。虚拟存储要解决逻辑卷与物理存储实体映射关系，可在计算机层、存储设备层、存储网络层解决。主机级虚拟化通过卷管理软件实现，成本低但平台依赖强、增加主机负担。存储设备级虚拟化由控制器实现，效率高、性能好，管理员有完全控制权，但存在厂商产品局限。网络级虚拟化由专用装置实现，可管理不同厂商设备，开放性好。此题中 C 是干扰项。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3193, 'question-system-analyst-2024-05-comprehensive-12034', '系统分析师', '软件架构设计', 2024, '2024年5月系统分析师综合知识-软件架构设计', 'TCP/IP 模型属于那种架构风格 （ 问题1 ） 。', '[{"key":"A","text":"层次风格","correct":true},{"key":"B","text":"管道风格","correct":false},{"key":"C","text":"黑板风格","correct":false},{"key":"D","text":"解释器风格","correct":false}]', 'A', '此题考察系统架构风格的相关辨析，属于基础题，建议必须掌握。分层架构是把系统分成系列层次，每层有特定功能且只与上下层交互，各层隐藏内部实现、暴露接口，使系统结构清晰、模块化、可维护。TCP/IP 模型分四层，应用层处理特定应用服务，传输层提供端到端通信服务，网络层负责数据包路由转发，链路层负责物理网络通信。属于典型的层次风格。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3194, 'question-system-analyst-2024-05-comprehensive-12035', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-网络体系结构与协议', '下列信号调制方式中，信道效率最高的是 （ 问题1 ） 。', '[{"key":"A","text":"SSB","correct":true},{"key":"B","text":"AM","correct":false},{"key":"C","text":"FM","correct":false},{"key":"D","text":"DSB","correct":false}]', 'A', '此题考察信号调制的相关内容，建议了解即可。指单位时间内传输的有效信息量，单位常为 bps。（1）SSB 调制是窄带方式，只传一侧频谱，带宽占用少，信道效率高。（2）AM 调制带宽占用大，信道效率较低。（3）FM 调制通过改频率传输信息，带宽占用比 AM 小，抗干扰和音质好，信道效率略低于 SSB 调制。（4）DSB 调制类似 AM 但不传输载波只有两个边带，需两倍边带带宽，信道效率比 AM 稍高但低于 SSB，因两个边带仍占更多带宽。', 1, 1, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3195, 'question-system-analyst-2024-05-comprehensive-12036', '系统分析师', '企业信息化', 2024, '2024年5月系统分析师综合知识-企业资源规划和实施', '产品生命周期含培育期、 （ 问题1 ） 、成熟期、衰退期、结束期5个阶段 。', '[{"key":"A","text":"成长期","correct":true},{"key":"B","text":"发展期","correct":false},{"key":"C","text":"建设期","correct":false},{"key":"D","text":"稳定期","correct":false}]', 'A', '此题考察产品生命周期的相关内容，出自书本第七章，建议了解即可。产品生命周期含培育期（概念期）、成长期、成熟期、衰退期、结束期（报废期）5 阶段，产品生命周期管理实施业务解决方案，将人、过程、信息有效集成，作用于企业，贯穿产品全生命周期，支持协作研发等与产品相关的对产品定义信息的管理、分发和使用。', 1, 1, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3196, 'question-system-analyst-2024-05-comprehensive-12037', '系统分析师', '面向对象分析方法', 2024, '2024年5月系统分析师综合知识-面向对象分析方法', '在 UML 类图关系中依赖性由强到弱排序为 （ 问题1 ） 。', '[{"key":"A","text":"泛化、组合、聚合、依赖","correct":true},{"key":"B","text":"聚合、组合、依赖、泛化","correct":false},{"key":"C","text":"聚合、泛化、依赖、组合","correct":false},{"key":"D","text":"聚合、依赖、组合、泛化","correct":false}]', 'A', '此题考察 UML 中类图的相关用法，属于常规高频考点，建议必须掌握。依赖关系指 B 变化可能引起 A 变化则 A 依赖 B。泛化关系是父类与子类关系。聚合关系表示整体与部分关系，部分可同时属多个整体，部分与整体生命周期不同（好聚好散）。组合关系也表示整体与部分关系，部分只能属一个整体，与整体生命周期相同（和聚合不同）。泛化是父子关系，是依赖性最强的关系，这里整体和部分的关系其次，所以组合和聚合排在前面。其中组合又比聚合强，所以选 A。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3197, 'question-system-analyst-2024-05-comprehensive-12038', '系统分析师', '网络工程', 2024, '2024年5月系统分析师综合知识-网络工程', '许多国家都在实施三网合一的系统工程，“三网”不包括 （ 问题1 ） 。', '[{"key":"A","text":"电信网","correct":false},{"key":"B","text":"数字电视网","correct":false},{"key":"C","text":"计算机网","correct":false},{"key":"D","text":"移动通信网","correct":true}]', 'D', '此题考察三网工程的理解，低频考点，建议了解即可。“三网”包括电信网、广播电视网、互联网。', 1, 1, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3198, 'question-system-analyst-2024-05-comprehensive-12039', '系统分析师', '计算机基础', 2024, '2024年5月系统分析师综合知识-计算机组成原理', '32 位原码可以表示的最小数值是 （ 问题1 ） 。', '[{"key":"A","text":"-(2^32-1)","correct":false},{"key":"B","text":"-(2^31-1)","correct":true},{"key":"C","text":"-(2^32+1)","correct":false},{"key":"D","text":"-(2^31+1)","correct":false}]', 'B', '此题考察计算机中原码的相关概念，建议必须掌握。原码是一种二进制定点表示方法。其符号位用“0”表示正号，用“1”表示负号，其余位表示数值的绝对值。例如，对于一个8位二进制数，正数 +5 的原码为：00000101，负数 -5 的原码为：10000101。原码的优点在于它直观简单，直接反映了数值的真值，但缺点是存在两个零（+0 和 -0），这在某些情况下可能会引起不必要的复杂性。此题中，第一位为符号位，剩下 31 位可以表示的最大数值是 2^31 - 1，那么当符号为为1的时候，可以取到负数，得到答案最大负数为 -(2^31-1)。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3199, 'question-system-analyst-2024-05-comprehensive-12040', '系统分析师', '法律法规', 2024, '2024年5月系统分析师综合知识-知识产权与专利', '企业到国家知识产权专利局申请专利的时候，审查员会依法审查，对发明专利、实用新型专利主要审查 （ 问题1 ） 。下列各项中，可以接受专利申请并授予专利权的是 （ 问题2 ） 。', '[{"key":"A","text":"新颖性、创造性、实用性","correct":true},{"key":"B","text":"不确定性、新颖性、创造性","correct":false},{"key":"C","text":"创造性、可改进性、实用性","correct":false},{"key":"D","text":"不确定性、可改进性、实用性","correct":false}]', 'A', '此题考察专利法的相关内容，最近年年考，建议必须掌握。根据《‌中华人民共和国专利法》‌，‌授予专利权的发明和实用新型，‌必须满足新颖性、‌创造性和实用性的要求。‌新颖性指的是该发明或实用新型不属于现有技术，‌即该技术或设计在申请日之前未被公开过；‌创造性是指与现有技术相比，‌该发明或实用新型具有突出的实质性特点和显著的进步；‌实用性则意味着该发明或实用新型能够被制造或使用，‌并能产生积极效果。同时，专利法第二十五条规定了不授予专利权的情形，包括：科学发现；智力活动的规则和方法；疾病的诊断和治疗方法；动物和植物品种；原子核变换方法以及用原子核变换方法获得的物质；对平面印刷品的图案、色彩或者二者的结合作出的主要起标识作用的设计。所以选择一项对某种型号的汽车发动机进行改进的技术方案。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3200, 'question-system-analyst-2024-05-comprehensive-12041', '系统分析师', '法律法规', 2024, '2024年5月系统分析师综合知识-知识产权与专利', '企业到国家知识产权专利局申请专利的时候，审查员会依法审查，对发明专利、实用新型专利主要审查 （ 问题1 ） 。下列各项中，可以接受专利申请并授予专利权的是 （ 问题2 ） 。', '[{"key":"A","text":"一种疾病的治疗和诊断方法","correct":false},{"key":"B","text":"一项对某种型号的汽车发动机进行改进的技术方案","correct":true},{"key":"C","text":"一项天文科学发现","correct":false},{"key":"D","text":"一项智力活动的规则和方法","correct":false}]', 'B', '此题考察专利法的相关内容，最近年年考，建议必须掌握。根据《‌中华人民共和国专利法》‌，‌授予专利权的发明和实用新型，‌必须满足新颖性、‌创造性和实用性的要求。‌新颖性指的是该发明或实用新型不属于现有技术，‌即该技术或设计在申请日之前未被公开过；‌创造性是指与现有技术相比，‌该发明或实用新型具有突出的实质性特点和显著的进步；‌实用性则意味着该发明或实用新型能够被制造或使用，‌并能产生积极效果。同时，专利法第二十五条规定了不授予专利权的情形，包括：科学发现；智力活动的规则和方法；疾病的诊断和治疗方法；动物和植物品种；原子核变换方法以及用原子核变换方法获得的物质；对平面印刷品的图案、色彩或者二者的结合作出的主要起标识作用的设计。所以选择一项对某种型号的汽车发动机进行改进的技术方案。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3201, 'question-system-analyst-2023-05-case-11897', '系统分析师', null, 2023, '2023年5月系统分析师案例分析-第1题', '试题一（25分）
阅读以下关于软件系统分析与建模的叙述，在纸上回答问题1至3。
【说明】
某软件公司拟开发—套汽车租赁系统,科学，安全和方便的管理租赁公司的各项业务，提高公司效率，提升利率。注册用户在使用系统镜像车辆预约时需执行以下操作:
- (a)用户登录系统
- (b)查询车辆信息
- (c)预订车辆
- (d)提取车辆
- (e)归还车辆
- (f)计算结余
- (g)查询换车时间

## 【问题1】（7分）
在面向对象软件分析过程中，状态机图和活动图用于建立软件的动态模型，主要描述系统随时间变化的行为，请分别阐述这两种图的概念和特点。

## 【问题2】（9分）
图1-1给出了采用状态机图描写的注册用户的状态交换过程，请使用题干给出的(a) ~ (g)补充完善图1-1中的(1) ~(7)，并给出（8）和(9)空白处的状态转移执行动作。将正确的答案填写在答题纸上。

## 【问题3】（9分）
RUP中有9个核心工作流,分6个核心过程和3个核心支持工作流。9个核心工作流在项目中迭代被使用在每次迭代中以不同的重点和强度重复。结合题干案例,用300字以内的文字简要说明RUP中9个核心工作流的主要作用。', '[]', '', '【问题1】
状态图(State Diagram)。状态图描述—个状态机，它由状态、转移、事件和活动组成。状态图给出了对象的动态视图。它对于接口、类或协作的行为建模尤为重要，而且它强调事件导致的对象行为，这非常有助于对反应式系统建模。
活动图(Activity Diagram)。活动图将进程或其他计算结构展示为计算内部步步的控制流和数据流。活动图专注于系统的动态视图。它对系统的功能建模和业务流程建模特别重要，并强调对象间的控制流程。
活动图是对行为流程的描述;状态机图是对属性值(状态)变化的描述。

【问题2】
(1): (a)用户登录系统
(2): (b)查询车辆信息
(3): (g)查询换车时间
(4): (c)预订车辆
(5): (e)归还车辆
(6): (d)提取车辆
(7): (f)计算结余
(8): 查询到有预定车辆
(9): 查询到无预定车辆

【问题3】
业务建模(Business Modeling)工作流描述了如何为新的目标组织开发一个构想，并基于这个构想在业务用例模型和商业对象模型中定义组织的过程，角色和责任。
需求(Requirement)工作流的目标是描述系统应该做什么，并使开发人员和用户就这—描述达成共识。为了达到该目标，要对需要的功能和约束进行提取、组织、文档化;最重要的是理解系统所解决问题的定义和范围。
分析和设计(Analysis &Design)工作流将需求转化成未来系统的设计，为系统开发一个健壮的结构并调整设计使其与实现环境相匹配，优化其性能。分析设计的结果是一个设计模型和一个可选的分析模型。设计模型是源代码的抽象,由设计类和—些描述组成。设计类被组织成具有良好接口的设计包(Package)和设计子系统(Subsystem)，而描述则体现了类的对象如何协同工作实现用例的功能。设计活动以体系结构设计为中心，体系结构由若干结构视图来表达，结构视图是整个设计的抽象和简化，该视图中省略了一些细节，使重要的特点体现得更加清晰。体系结构不仅仅是良好设计模型的承载媒介，而且在系统的开发中能提高被创建模型的质量。
实现(Implementation)工作流的目的包括以层次化的子系统形式定义代码的组织结构;以组件的形式(源文件、二进制文件、可执行文件)实现类和对象;将开发出的组件作为单元进行测试以及集成由单个开发者(或小组)所产生的结果，使其成为可执行的系统。
测试(Test)工作流要验证对象间的交互作用，验证软件中所有组件的正确集成，检验所有的需求已被正确的实现，识别并确认缺陷在软件部署之前被提出并处理。RUP提出了迭代的方法，意味着在整个项目中进行测试，从而尽可能早地发现缺陷，从根本上降低了修改缺陷的成本。测试类似于三维模型，分别从可靠性、功能性和系统性能来进行。
部署(Deployment)工作流的目的是成功的生成版本并将软件分发给最终用户。部署工作流描述了那些与确保软件产品对最终用户具有可用性相关的活动，包括:软件打包、生成软件本身以外的产品、安装软件、为用户提供帮助。在有些情况下，还可能包括计划和进行beta测试版、移植现有的软件和数据以及正式验收。
配置和变更管理工作流描绘了如何在多个成员组成的项目中控制大量的产物。配置和变更管理工作流提供了准则来管理演化系统中的多个变体，跟踪软件创建过程中的版本。工作流描述了如何管理并行开发、分布式开发、如何自动化创建工程。同时也阐述了对产品修改原因、时间、人员保持审计记录。
软件项目管理(Project Management)平衡各种可能产生冲突的目标，管理风险，克服各种约束并成功交付使用户满意的产品。其目标包括:为项目的管理提供框架,为计划、人员配备、执行和监控项目提供实用的准则，为管理风险提供框架等。
环境(Environment)工作流的目的是向软件开发组织提供软件开发环境，包括过程和工具。环境工作流集中于配置项目过程中所需要的活动，同样也支持开发项目规范的活动，提供了逐步的指导手册并介绍了如何在组织中实现过程。

【问题1】
状态图(State Diagram)。状态图描述—个状态机，它由状态、转移、事件和活动组成。状态图给出了对象的动态视图。它对于接口、类或协作的行为建模尤为重要，而且它强调事件导致的对象行为，这非常有助于对反应式系统建模。
活动图(Activity Diagram)。活动图将进程或其他计算结构展示为计算内部步步的控制流和数据流。活动图专注于系统的动态视图。它对系统的功能建模和业务流程建模特别重要，并强调对象间的控制流程。
活动图是对行为流程的描述;状态机图是对属性值(状态)变化的描述。

【问题2】
(1): (a)用户登录系统
(2): (b)查询车辆信息
(3): (g)查询换车时间
(4): (c)预订车辆
(5): (e)归还车辆
(6): (d)提取车辆
(7): (f)计算结余
(8): 查询到有预定车辆
(9): 查询到无预定车辆

