INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3205, 'question-system-analyst-2023-05-case-11901', '系统分析师', null, 2023, '2023年5月系统分析师案例分析-第5题', '试题五（25分）
阅读下列说明，回答问题1至问题3，将解答填入答题纸的对应栏内。
【说明】
某公司拟开发一个电商平台用户行为分析系统，该系统可支持对电商平台用户行为数据的采集和实时/高效数据处理分析，统计分析用户访问情况。搜集PV/UV商品热度等相关数据。系统应具备以下能力
(1)对海量用户行为数据的存储和处理能力
(2)为适应用户行为的随机性,保证系统不会被爆发的日志数据压垮，系统应具备对突发流量的处理能力
(3)对用户数据的营私保护能力
针对项目需求，工时召开会议，会上张工提出买那个对大量数据，传统的文件存储于关系型数据库，无法完全解决当前系统问题，应基于大数据技术设计并实现系统，李工提出可就要数据脱敏的方法解决用户隐私的问题
【问题1】
根据项目要求，该系统需考虑电商平台用户行为的随机性，具有应对突发数据，流量数据的处理能力。请给予大数据相关技术的了解，说明可选那个技术支持流系统应对突发流量暴增情况?并用200字以内说明该技术优势
【问题2】
