INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3288, 'question-system-analyst-2022-05-thesis-11838', '系统分析师', null, 2022, '2022年5月系统分析师论文-第1题', '论原型法及其在信息系统开发中的应用 作为一种信息系统开发方法，原型法（Prototyping）被普遍使用，原型法是指在获取一组基本的需求定义后，利用可视化的开发工具，快速建立一个目标系统的最初版本，并交由用户试用，并根据用户反馈进行补充和修改，再形成新的版本。反复进行这个过程，直到得出系统的“精确解”，即用户满意为止。
请围绕“原型法及其在信息系统开发中的应用”论题，依次从以下三个方面进行论述。 1.概要叙述你参与管理和开发的软件项目以及你在其中所承担的主要工作。 2.请简要描述原型法的开发过程。 3.具体阐述你参与管理和开发的项目是如何基于原型法进行信息系统开发的。', '[]', '', '论文暂无解析

论文暂无解析', 1, 2, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3289, 'question-system-analyst-2022-05-thesis-11839', '系统分析师', null, 2022, '2022年5月系统分析师论文-第2题', '论面向对象设计方法及其应用 系统设计是根据系统分析的结果，运用系统科学的思想和方法，设计出能满是用户所要求的目标（或目的）系统的过程。面向对象设计方法是一种接近现实的系统设计方法。在该方法中，数据结构和在数据结构上定义的操作算法封装在一个对象之中。
请围绕“面向对象设计方法及其应用”论题，依次从以下三个方面进行论述。 1.概要叙述你参与管理和开发的软件项目以及你在其中所承担的主要工作。 2.面向对象设计方法包含多种设计原则，请简要描述其中的三种设计原则。 3.具体阐述你参与管理和开发的项目是如何遵循这三种设计原则进行信息系统设计的。', '[]', '', '论文暂无解析

论文暂无解析', 1, 2, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3290, 'question-system-analyst-2022-05-comprehensive-13203', '系统分析师', '需求工程', 2022, '2022年5月系统分析师综合知识-面向对象分析方法', 'UML中的 （ 问题1 ） 主要用于参与者与系统中对象之间的交互，以及这些对象之间交互的建模。', '[{"key":"A","text":"顺序图","correct":true},{"key":"B","text":"活动图","correct":false},{"key":"C","text":"用例图","correct":false},{"key":"D","text":"状态图","correct":false}]', 'A', '此题考察 UML2.0 的14种视图，比较偏门，建议记住此题的概念即可。顺序图主要用于对参与者与系统对象之间、系统对象自身之间的交互进行建模。顺序图显示对象之间的动态合作关系，它强调对象之间消息发送的顺序，同时显示对象之间的交互顺序图的一个用途是用来表示用例中的行为顺序。当执行一个用例行为时，顺序图中的每条消息对应了一个类操作或引起状态转换的触发事件。有的同学会问为啥不选 C，用例图虽然也可以反应参与者与系统中对象之间的交互，但是后半句对象之间交互，用例图做不到。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3291, 'question-system-analyst-2022-05-comprehensive-13199', '系统分析师', '需求工程', 2022, '2022年5月系统分析师综合知识-需求工程概述', '（ 问题1 ） 是从系统的应用领域而不是从系统用户的特定需要中得出的，它们可以是新的功能性需求，或者是对已有功能性需求的约束，或者是陈述特定的计算必须遵守的要求。', '[{"key":"A","text":"功能性需求","correct":false},{"key":"B","text":"用户需求","correct":false},{"key":"C","text":"产品需求","correct":false},{"key":"D","text":"领域需求","correct":true}]', 'D', '此题属于超纲题，书本并未对领域需求有做描述，建议了解即可。领域需求是指在特定领域内，对于某项产品或服务所要求的具体功能和规格，以及对于这些功能和规格的使用环境和性能要求的描述。领域需求是从系统的应用领域而不是从系统用户的特定需要中得出的。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3292, 'question-system-analyst-2022-05-comprehensive-13237', '系统分析师', '软件工程', 2022, '2022年5月系统分析师综合知识-逆向工程', '在软件逆向工程的相关概念中， （ 问题1 ） 是指借助工具从已有程序中抽象出有关数据设计、总体结构设计和过程设计等方面的信息； （ 问题2 ） 指不仅从现有系统中恢复设计信息，而且使用该信息去改变或重构现有系统，以改善其整体质量。', '[{"key":"A","text":"再工程","correct":false},{"key":"B","text":"需求工程","correct":false},{"key":"C","text":"正向工程","correct":true},{"key":"D","text":"逆向工程","correct":false}]', 'C', '此题考察了逆向工程的相关概念，出自书本8.2.2，建议掌握。逆向工程涉及的概念包括重构、设计恢复、再工程和正向工程。重构是在同一抽象级别上转换系统描述形式，设计恢复是借助工具从已有程序中抽象出设计信息，再工程是基于逆向工程信息修改或重构系统产生新版本，正向工程不仅恢复设计信息，而且使用该信息去重构或改变现有系统，以改善其整体质量。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3293, 'question-system-analyst-2022-05-comprehensive-13236', '系统分析师', '软件工程', 2022, '2022年5月系统分析师综合知识-逆向工程', '在软件逆向工程的相关概念中， （ 问题1 ） 是指借助工具从已有程序中抽象出有关数据设计、总体结构设计和过程设计等方面的信息； （ 问题2 ） 指不仅从现有系统中恢复设计信息，而且使用该信息去改变或重构现有系统，以改善其整体质量。', '[{"key":"A","text":"设计恢复","correct":true},{"key":"B","text":"正向工程","correct":false},{"key":"C","text":"设计重构","correct":false},{"key":"D","text":"重构","correct":false}]', 'A', '此题考察了逆向工程的相关概念，出自书本8.2.2，建议掌握。逆向工程涉及的概念包括重构、设计恢复、再工程和正向工程。重构是在同一抽象级别上转换系统描述形式，设计恢复是借助工具从已有程序中抽象出设计信息，再工程是基于逆向工程信息修改或重构系统产生新版本，正向工程不仅恢复设计信息，而且使用该信息去重构或改变现有系统，以改善其整体质量。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3294, 'question-system-analyst-2022-05-comprehensive-13225', '系统分析师', '软件工程', 2022, '2022年5月系统分析师综合知识-软件过程管理', 'ISO 9000 定义业务过程（Business Process）为一组将输入转化为输出的相互关联或相互作用的活动。该过程包括六个基本要素，分别是 （ 问题1 ） 、活动、活动的相互作用、输出结果、用户和价值。', '[{"key":"A","text":"输入资源","correct":true},{"key":"B","text":"需求说明","correct":false},{"key":"C","text":"活动环境","correct":false},{"key":"D","text":"活动前提","correct":false}]', 'A', '此题考察质量管理标准相关知识，属于超纲题，建议了解即可。ISO 9000 有关业务流程的定义是业务流程是一组将输入转化为输出的相互关联或相互作用的活动。流程六个要素分别是输入、活动、活动的相互作用（即结构）、输出、客户、价值。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3295, 'question-system-analyst-2022-05-comprehensive-13202', '系统分析师', '软件工程', 2022, '2022年5月系统分析师综合知识-开发模型', '敏捷软件开发方法是一种增量式开发方法，它将 （ 问题1 ） 视为软件过程的中心活动，将其他开发活动融入其中。', '[{"key":"A","text":"可行性分析","correct":false},{"key":"B","text":"需求分析和设计","correct":false},{"key":"C","text":"设计和实现","correct":false},{"key":"D","text":"实现和测试","correct":true}]', 'D', '此题考察软件开发模型中的敏捷方法，出自书本8.3.4。建议了解即可。敏捷开发方法是以人为核心、迭代、逐步推进的一种开发方式。它将整个软件项目切分成多个子项目，每个子项目都经过测试，并具有集成和可运行的特性，开发者需要关注短平快的会议、小版本发布、合作和客户参与、自动化测试和结对编程等方面，而管理者需要重视测试驱动开发、持续集成和重构等方面。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3296, 'question-system-analyst-2022-05-comprehensive-13268', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-网络体系结构与协议', 'IP地址 10.10.33.66 /16 的网络地址是 （ 问题1 ） 。', '[{"key":"A","text":"10.10.0.0","correct":true},{"key":"B","text":"10.0.0.0","correct":false},{"key":"C","text":"10.10.33.0","correct":false},{"key":"D","text":"10.10.33.1","correct":false}]', 'A', '此题考查网络地址与分配相关知识，出自书本4.2.3章节，建议必须掌握。无分类域间路由（CIDR）划分子网在一定程度上缓解了 Internet在发展中遇到的问题。CIDR消除了传统IP地址的分类和划分子网的概念，可以更加有效地分配IPv4的地址空间。CIDR把32位的IP地址划分为两个部分：前面的部分为网络前缀，用来指明网络；后面的部分用来表示主机。它的记法为在IP地址后加上斜线“1”，然后在后面写上网络前缀所占的位数，例如，128.2.3.4/20表示网络前缀为高20位，主机号为低12位。

此题中， /16 表示子网掩码为 255.255.0.0，即前 16 位（前两个字节）为网络位，后 16 位（后两个字节）为主机位。网络地址 = IP地址 与 子网掩码（按位与操作）。得到网络地址为 10.10.0.0。所以选择选项A。这里需要补充的是，网络号与子网号的关系。网络号是 IP 地址中标识主网络的全局部分，由 CIDR 前缀长度决定（如 /19）。子网号是划分子网后，从原网络的主机位中借用部分位形成的，划分之后这个网络的CIDR表示也会改变。

还有更快捷的算法 ：

**主机号全为 0 的地址即是网络地址。**

根据CIDR的表示方法，我们已经知道了前 16 位（前两个字节）为网络位，**后 16 位（后两个字节）为主机位**，所以直接得出 网络地址为 10.10.**0.0** 。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3297, 'question-system-analyst-2022-05-comprehensive-13267', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-网络体系结构与协议', 'IP报文首部不包含 （ 问题1 ） 。', '[{"key":"A","text":"版本号","correct":false},{"key":"B","text":"源目的MAC","correct":true},{"key":"C","text":"生存时间","correct":false},{"key":"D","text":"源/目的IP","correct":false}]', 'B', '此题考察 IP 报文的相关概念，属于超纲题，建议了解即可。IP报文首部主要包含四个部分分别版本号、首部长度、区分服务、总长度；标识、标志、片偏移；生存时间、协议、首部校验和；源IP、目标IP。其中，每个部分都承载着不同的信息，如版本号表示使用的IP协议版本，总长度表示整个IP报文（包括首部和数据部分）的总长度等。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3298, 'question-system-analyst-2022-05-comprehensive-13265', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-网络体系结构与协议', '下列协议中，不属于电子邮件收发协议的是 （ 问题1 ） 。', '[{"key":"A","text":"SMTP","correct":false},{"key":"B","text":"POP","correct":false},{"key":"C","text":"IMAP","correct":false},{"key":"D","text":"FTP","correct":true}]', 'D', '此题考查的是电子邮件相关协议，属于超纲题，建议了解即可。电子邮件协议通常包括 SMTP 和 POP3 作为发送和接收协议，而 MIME 则扩展了电子邮件标准以支持非ASCII字符文本、非文本格式附件、多部分消息体和含有非 ASCII 字符的头信息。IMAP 和 POP3 的区别在于，POP3 协议只能在客户端下载并操作邮件，操作不反馈到服务器上，而 IMAP 客户端操作会反馈到服务器上。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3299, 'question-system-analyst-2022-05-comprehensive-13264', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-网络体系结构与协议', 'DNS 协议的功能是 （ 问题1 ） 。', '[{"key":"A","text":"将域名解析为IP地址","correct":true},{"key":"B","text":"将MAC地址解析为IP地址","correct":false},{"key":"C","text":"将IP地址解析为MAC地址","correct":false},{"key":"D","text":"将主机名解析为IP地址","correct":false}]', 'A', '本题考查 DNS 协议的基本概念，属于超纲题，建议了解即可。DNS 协议的主要功能是将易于记忆的域名 (如 www.example.com) 转换为计算机网络中的 IP 地址 (如 192.0.2.1)。DNS 协议通过分布式的域名服务器来实现这一功能，使得互联网上的计算机可以准确地定位其他计算机、服务或资源。DNS 协议还提供一些其他的功能，如反向查询、邮件交换记录 (MX 记录)、别名记录 (CNAME 记录) 等。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3300, 'question-system-analyst-2022-05-comprehensive-13204', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-网络体系结构与协议', 'TCP/IP 的四层模型中，每一层都提供了安全协议，下列属于网络层安全协议的是 （ 问题1 ） 。', '[{"key":"A","text":"HTTPS","correct":false},{"key":"B","text":"SSH","correct":false},{"key":"C","text":"IPSec","correct":true},{"key":"D","text":"Socks","correct":false}]', 'C', '此题考察网络层安全协议的基本知识，建议了解即可。常见的网络层安全协议有 IPsec——提供一种安全的传输方式，可以对 IP数据报进行加密、身份验证和完整性保护。SSL和TLS——用于加密传输层数据的协议，常用于Web浏览器和服务器之间的通信。L2TP——主要用于虚拟专用网络（VPN）的建立和管理，具有加密、完整性检查和身份验证功能。GRE——用于构建虚拟专用网络（VPN）的协议，可以在IP数据报中封装其他协议的数据。 PPTP——用于建立安全的远程访问连接，可提供加密和身份验证功能。IPSec 属于网络层安全协议。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3301, 'question-system-analyst-2022-05-comprehensive-13258', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-系统性能评估', '计算机系统性能评估中， （ 问题1 ） 通常采用加法指令的运算速度来衡量计算机的速度。 （ 问题2 ） 首先计算出处理部件每个计算单元的有效计算率，再按不同字长加以调整，得出该计算单元的理论性能，所有组成该处理部件的计算单元的理论性能之和即为最终的计算机性能。', '[{"key":"A","text":"指令执行速度法","correct":false},{"key":"B","text":"等效指令速度法","correct":false},{"key":"C","text":"综合理论性能法","correct":true},{"key":"D","text":"基准程序法","correct":false}]', 'C', '此题考查计算机系统的性能评估方法的基本概念，出自书本6.8.2章节，建议掌握。性能评估方法包括指令执行速度法、等效指令速度法、综合理论性能法和基准程序法。指令执行速度法以加法指令的运算速度为代表，用MIPS表示机器运算速度。等效指令速度法通过各类指令在程序中所占的比例来计算机器的速度，但不适用于CISC系统。综合理论性能法采用CTP方法来评估运算部件的综合性能，用MTOPS表示。基准程序法是一种改进方案，适用于老一代系统，评价更全面，可以考虑到I/O结构、操作系统、编译程序等对系统性能的影响。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3302, 'question-system-analyst-2022-05-comprehensive-13257', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-系统性能评估', '计算机系统性能评估中， （ 问题1 ） 通常采用加法指令的运算速度来衡量计算机的速度。 （ 问题2 ） 首先计算出处理部件每个计算单元的有效计算率，再按不同字长加以调整，得出该计算单元的理论性能，所有组成该处理部件的计算单元的理论性能之和即为最终的计算机性能。', '[{"key":"A","text":"指令执行速度法","correct":true},{"key":"B","text":"等效指令速度法","correct":false},{"key":"C","text":"综合理论性能法","correct":false},{"key":"D","text":"基准程序法","correct":false}]', 'A', '此题考查计算机系统的性能评估方法的基本概念，出自书本6.8.2章节，建议掌握。性能评估方法包括指令执行速度法、等效指令速度法、综合理论性能法和基准程序法。指令执行速度法以加法指令的运算速度为代表，用MIPS表示机器运算速度。等效指令速度法通过各类指令在程序中所占的比例来计算机器的速度，但不适用于CISC系统。综合理论性能法采用CTP方法来评估运算部件的综合性能，用MTOPS表示。基准程序法是一种改进方案，适用于老一代系统，评价更全面，可以考虑到I/O结构、操作系统、编译程序等对系统性能的影响。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3303, 'question-system-analyst-2022-05-comprehensive-13230', '系统分析师', '系统设计', 2022, '2022年5月系统分析师综合知识-面向对象设计', '在面向对象方法中，一个子类有多个父类，可以从多个父类中继承特性，这种继承称为 （ 问题1 ） 。 对于两个类A和B，如果A是B的子类，则B是A的 （ 问题2 ） 。', '[{"key":"A","text":"聚合","correct":false},{"key":"B","text":"泛化","correct":true},{"key":"C","text":"聚类","correct":false},{"key":"D","text":"耦合","correct":false}]', 'B', '一个子类有多个父类，可以从多个父类中继承特性，这种继承称为多重继承。 对于两个类A和B，如果A是B的子类，则B是A的泛化。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3304, 'question-system-analyst-2022-05-comprehensive-13229', '系统分析师', '系统设计', 2022, '2022年5月系统分析师综合知识-面向对象设计', '在面向对象方法中，一个子类有多个父类，可以从多个父类中继承特性，这种继承称为 （ 问题1 ） 。 对于两个类A和B，如果A是B的子类，则B是A的 （ 问题2 ） 。', '[{"key":"A","text":"多重继承","correct":true},{"key":"B","text":"单一继承","correct":false},{"key":"C","text":"多例继承","correct":false},{"key":"D","text":"单例继承","correct":false}]', 'A', '此题考察信息系统开发方法中的面向对象方法——出自书本7.3.2，建议记住即可。一个子类有多个父类，可以从多个父类中继承特性，这种继承称为多重继承。 对于两个类A和B，如果A是B的子类，则B是A的泛化。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3305, 'question-system-analyst-2022-05-comprehensive-13232', '系统分析师', '系统设计', 2022, '2022年5月系统分析师综合知识-结构化设计', '结构化设计 （Structured Design, SD）是一种面向数据流的方法，可进一步细分为 （ 问题1 ） 两个阶段，它根据 （ 问题2 ） 和系统结构准则，将DFD转换为系统结构图，用系统结构图来建立系统的物理模型，描述系统分层次的模块结构，以及模块之间的通信与控制关系。', '[{"key":"A","text":"模块耦合性原则","correct":false},{"key":"B","text":"模块独立性原则","correct":true},{"key":"C","text":"自顶向下原则","correct":false},{"key":"D","text":"自底向上原则","correct":false}]', 'B', '此题纯纯的概念题，考察结构化设计（Structured Design, SD）的基本概念——书本7.3.1明确指出了它的定义。提示大家要注意记住它的概念，他们在案例，论文可能都会出现。首先结构化设计是一种面向数据流的方法，它以SRS和SA阶段所产生的数据流图和数据字典等文档为基础，是一个自顶向下、逐步求精和模块化的过程。其次，它的基本思想是将软件设计成由相对独立且具有单一功能的模块组成的结构。设计过程分为概要设计和详细设计两个阶段，其中概要设计的主要任务是确定软件系统的结构，对系统进行模块划分，确定每个模块的功能、接口和模块之间的调用关系；详细设计的主要任务是为每个模块设计实现的细节。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3306, 'question-system-analyst-2022-05-comprehensive-13231', '系统分析师', '系统设计', 2022, '2022年5月系统分析师综合知识-结构化设计', '结构化设计 （Structured Design, SD）是一种面向数据流的方法，可进一步细分为 （ 问题1 ） 两个阶段，它根据 （ 问题2 ） 和系统结构准则，将DFD转换为系统结构图，用系统结构图来建立系统的物理模型，描述系统分层次的模块结构，以及模块之间的通信与控制关系。', '[{"key":"A","text":"概要设计和详细设计","correct":true},{"key":"B","text":"数据库设计和架构设计","correct":false},{"key":"C","text":"概要设计和架构设计","correct":false},{"key":"D","text":"模块设计和数据设计","correct":false}]', 'A', '此题纯纯的概念题，考察结构化设计（Structured Design, SD）的基本概念——书本7.3.1明确指出了它的定义。提示大家要注意记住它的概念，他们在案例，论文可能都会出现。首先结构化设计是一种面向数据流的方法，它以SRS和SA阶段所产生的数据流图和数据字典等文档为基础，是一个自顶向下、逐步求精和模块化的过程。其次，它的基本思想是将软件设计成由相对独立且具有单一功能的模块组成的结构。设计过程分为概要设计和详细设计两个阶段，其中概要设计的主要任务是确定软件系统的结构，对系统进行模块划分，确定每个模块的功能、接口和模块之间的调用关系；详细设计的主要任务是为每个模块设计实现的细节。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3307, 'question-system-analyst-2022-05-comprehensive-13228', '系统分析师', '系统设计', 2022, '2022年5月系统分析师综合知识-流程设计', '工作流参考模型（Workflow Reference Model，WRM）包含6个基本模块，分别是 （ 问题1 ） 、工作流引擎、流程定义工具、 （ 问题2 ） 、调用应用和管理监控工具。', '[{"key":"A","text":"客户端应用","correct":true},{"key":"B","text":"服务端应用","correct":false},{"key":"C","text":"部署端应用","correct":false},{"key":"D","text":"网络端应用","correct":false}]', 'A', '', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3308, 'question-system-analyst-2022-05-comprehensive-13227', '系统分析师', '系统设计', 2022, '2022年5月系统分析师综合知识-流程设计', '工作流参考模型（Workflow Reference Model，WRM）包含6个基本模块，分别是 （ 问题1 ） 、工作流引擎、流程定义工具、 （ 问题2 ） 、调用应用和管理监控工具。', '[{"key":"A","text":"工作流执行服务","correct":true},{"key":"B","text":"流程服务引擎","correct":false},{"key":"C","text":"服务标准引擎","correct":false},{"key":"D","text":"流程设计工具","correct":false}]', 'A', '此题考察的是书本第十三章流程设计的概念，此题是概念题，历年考察也不多，跟着了解即可。工作流参考模型（Workflow Reference Model，WRM）是由六个基本模块构成的，包括工作流执行服务、工作流引擎、流程定义工具、客户端应用、调用应用和管理监控工具。工作流执行服务是WFMS的核心模块，它的功能包括创建和管理流程定义，创建、管理和执行流程实例。工作流引擎是为流程实例提供运行环境，并解释执行流程实例的软件模块。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3309, 'question-system-analyst-2022-05-comprehensive-13226', '系统分析师', '系统设计', 2022, '2022年5月系统分析师综合知识-流程设计', '工作流管理系统（Workflow Management System，WFMS）通过软件定义、创建工作流并管理其执行。其中，监控和管理进度完成情况和数据所处状态、工作分配与均衡情况等执行中的业务，体现着工作流管理系统 （ 问题1 ） 的基本功能。', '[{"key":"A","text":"工作流执行","correct":false},{"key":"B","text":"业务过程的设计和实现","correct":false},{"key":"C","text":"业务过程管理和分析","correct":true},{"key":"D","text":"对工作流进行建模","correct":false}]', 'C', '此题考察的是书本第十三章流程设计的概念，此题是概念题，历年考察也不多，跟着了解即可。根据 WFMC（工作流管理联盟）的定义，工作流管理系统（WFMS）通过软件定义、创建工作流并管理其执行。它运行在一个或多个工作流引擎上，这些引擎解释对过程的定义与工作流的参与者相互作用，并根据需要调用其他IT工具或应用。工作流参考模型是由六个基本模块构成的，包括工作流执行服务、工作流引擎、流程定义工具、客户端应用、调用应用和管理监控工具。工作流执行服务是WFMS的核心模块，它的功能包括创建和管理流程定义，创建、管理和执行流程实例。工作流引擎是为流程实例提供运行环境，并解释执行流程实例的软件模块。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3310, 'question-system-analyst-2022-05-comprehensive-13266', '系统分析师', '系统安全性分析与设计', 2022, '2022年5月系统分析师综合知识-通信与网络安全技术', '某信息系统不断受到 SQL 注入攻击，应部署 （ 问题1 ） 进行安全防护，实时阻断攻击行为。', '[{"key":"A","text":"防火墙","correct":false},{"key":"B","text":"WEB 防火墙","correct":true},{"key":"C","text":"入侵检测系统","correct":false},{"key":"D","text":"堡垒机","correct":false}]', 'B', '此题考察系统 WEB 防火墙的相关概念，建议了解即可。不断受到 SQL 注入攻击，应部署 WEB 防火墙进行安全防护，实时阻断攻击行为。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3311, 'question-system-analyst-2022-05-comprehensive-13206', '系统分析师', '系统安全性分析与设计', 2022, '2022年5月系统分析师综合知识-系统安全与保密', '（ 问题1 ） 属于公钥加密算法。', '[{"key":"A","text":"AES","correct":false},{"key":"B","text":"RSA","correct":true},{"key":"C","text":"MD5","correct":false},{"key":"D","text":"DES","correct":false}]', 'B', '此题考查的是信息安全中的加密算法，出自书本18.2.1章节，超纲题，建议必须掌握。常见的对称加密算法包括 DES，3DES，RC-5，IDEA，AES，常见的非对称加密算法包括 RSA，ECC，Elgamal、背包算法、Rabin、D-H。常见的信息摘要算法包括 SHA，MD5，HMAC。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3312, 'question-system-analyst-2022-05-comprehensive-13205', '系统分析师', '系统安全性分析与设计', 2022, '2022年5月系统分析师综合知识-系统安全与保密', '（ 问题1 ） 不属于基于生物特征的认证技术。', '[{"key":"A","text":"指纹识别","correct":false},{"key":"B","text":"人脸识别","correct":false},{"key":"C","text":"口令","correct":true},{"key":"D","text":"虹膜识别","correct":false}]', 'C', '此题考察身份认证技术的相关概念，出自书本 18.2.2 章节，建议了解即可。生物特征识别技术是一种利用人类生物特征进行身份认证的技术，这些生物特征具有唯一、可测量或自动识别、遗传性或终身不变等特点。该技术的核心在于获取这些生物特征，并将其转换为数字信息，在计算机中存储，利用可靠的匹配算法完成身份验证和识别。身体特征包括指纹、静脉、掌型、视网膜、虹膜、人体气味、脸型、血管、DNA、骨骼等。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3313, 'question-system-analyst-2022-05-comprehensive-13263', '系统分析师', '系统安全性分析与设计', 2022, '2022年5月系统分析师综合知识-信息系统安全体系', '下列协议中， 可以用于文件安全传输的是 （ 问题1 ） 。', '[{"key":"A","text":"FTP","correct":false},{"key":"B","text":"SFTP","correct":true},{"key":"C","text":"TFTP","correct":false},{"key":"D","text":"ICMP","correct":false}]', 'B', '此题考察网络安全协议，出自书本 18.3.3 章节，建议了解即可。可以用于文件安全传输的是 SFTP。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3314, 'question-system-analyst-2022-05-comprehensive-13260', '系统分析师', '系统安全性分析与设计', 2022, '2022年5月系统分析师综合知识-信息系统安全体系', '信息系统的安全是一个复杂的综合体，涉及系统的方方面面， 其中 （ 问题1 ） 是指保护计算机设备、设施和其他媒体免遭地震、水灾、火灾、有害气体和其他环境事故（例如，电磁辐射等）破坏的措施和过程。 （ 问题2 ） 是计算机信息系统安全的重要环节，其实质是保证系统的正常运行，不因偶然的或恶意的侵扰而遭到破坏，使系统可靠、连续地运行，服务不被中断。', '[{"key":"A","text":"信息安全","correct":false},{"key":"B","text":"人员安全","correct":false},{"key":"C","text":"运行安全","correct":true},{"key":"D","text":"实体安全","correct":false}]', 'C', '此题考查计算机信息系统的安全体系，出自书本18.1章节，建议了解即可。信息系统的安全是个复杂的综合体，涉及系统的方方面面， 其中实体安全是指保护计算机设备、设施和其他媒体免遭地震、水灾、火灾、有害气体和其他环境事故（例如，电磁辐射等）破坏的措施和过程。运行安全是计算机信息系统安全的重要环节，其实质是保证系统的正常运行，不因偶然的或恶意的侵扰而遭到破坏，使系统可靠、连续地运行，服务不被中断。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3315, 'question-system-analyst-2022-05-comprehensive-13259', '系统分析师', '系统安全性分析与设计', 2022, '2022年5月系统分析师综合知识-信息系统安全体系', '信息系统的安全是一个复杂的综合体，涉及系统的方方面面， 其中 （ 问题1 ） 是指保护计算机设备、设施和其他媒体免遭地震、水灾、火灾、有害气体和其他环境事故（例如，电磁辐射等）破坏的措施和过程。 （ 问题2 ） 是计算机信息系统安全的重要环节，其实质是保证系统的正常运行，不因偶然的或恶意的侵扰而遭到破坏，使系统可靠、连续地运行，服务不被中断。', '[{"key":"A","text":"信息安全","correct":false},{"key":"B","text":"人员安全","correct":false},{"key":"C","text":"运行安全","correct":false},{"key":"D","text":"实体安全","correct":true}]', 'D', '此题考查计算机信息系统的安全体系，出自书本18.1章节，建议了解即可。信息系统的安全是个复杂的综合体，涉及系统的方方面面， 其中实体安全是指保护计算机设备、设施和其他媒体免遭地震、水灾、火灾、有害气体和其他环境事故（例如，电磁辐射等）破坏的措施和过程。运行安全是计算机信息系统安全的重要环节，其实质是保证系统的正常运行，不因偶然的或恶意的侵扰而遭到破坏，使系统可靠、连续地运行，服务不被中断。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3316, 'question-system-analyst-2022-05-comprehensive-13207', '系统分析师', '系统安全性分析与设计', 2022, '2022年5月系统分析师综合知识-信息系统安全体系', '确保计算机系统机密性的方法不包括 （ 问题1 ） 。', '[{"key":"A","text":"加密","correct":false},{"key":"B","text":"认证","correct":false},{"key":"C","text":"授权","correct":false},{"key":"D","text":"备份","correct":true}]', 'D', '此题考察信息系统安全体系相关知识，出自书本 18.1 章节属于常识题，建议必须掌握。确保计算机系统机密性的方法不包括备份。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3317, 'question-system-analyst-2022-05-comprehensive-13200', '系统分析师', '系统安全性分析与设计', 2022, '2022年5月系统分析师综合知识-信息系统安全体系', '对于安全关键系统，需要额外的安全保证、软件验证以及系统分析过程。 （ 问题1 ） 是检查系统是否安全运行的一组活动，包含在软件开发过程的所有阶段中，记录了所进行的分析以及负责分析的相关人员。', '[{"key":"A","text":"软件测试","correct":false},{"key":"B","text":"安全保证","correct":true},{"key":"C","text":"软件验证","correct":false},{"key":"D","text":"系统分析","correct":false}]', 'B', '此题考察安全保证的相关概念，属于超纲题，建议了解即可。安全保证是检查系统是否安全运行的一组活动，包含在软件开发过程的所有阶段中，记录了所进行的分析以及负责分析的相关人员。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3318, 'question-system-analyst-2022-05-comprehensive-13210', '系统分析师', '法律法规', 2022, '2022年5月系统分析师综合知识-著作权', '郭一在单位运营管理部工作，负责经营报表和统计分析，为便于及时、准确完成报表，郭一利用自身软件开发基础，在下班后的业余时间与家人共同开发了一个统计软件。以下说法中，正确的是 （ 问题1 ） 。', '[{"key":"A","text":"该软件没有商业用途，没有著作权的问题","correct":false},{"key":"B","text":"郭一在开发软件的过程中，没有利用企业的物质技术条件，该软件的著作权属于郭一","correct":false},{"key":"C","text":"按照软件著作权归属的一般原则，该软件的著作权归属于郭一","correct":false},{"key":"D","text":"该软件的著作权属于企业，因其是郭一为完成本职工作而产生的结果","correct":true}]', 'D', '此题考察著作权法的相关知识，建议掌握即可。“为便于及时、准确完成报表，郭一利用自身软件开发基础，在下班后的业余时间与家人共同开发了一个统计软件”与本职工作相关的软件产物，属于典型的职务作品，该软件著作权属于企业所有。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3319, 'question-system-analyst-2022-05-comprehensive-13209', '系统分析师', '法律法规', 2022, '2022年5月系统分析师综合知识-著作权', '下列关于计算机软件著作权的叙述，错误的是 （ 问题1 ） 。', '[{"key":"A","text":"为了学习和研究软件内涵的设计思想和原理，通过安装、传输或存储软件等方式使用软件，可以不经软件著作权人许可，不向其支付报酬","correct":false},{"key":"B","text":"软件著作权属于自然人的，该自然人死亡后，在软件著作权的保护期内，软件著作权的继承人可以继承各项软件著作权","correct":true},{"key":"C","text":"软件著作权人可以许可他人行使其软件著作权，并有权获得报酬","correct":false},{"key":"D","text":"软件著作权人可以全部或部分转让其软件著作权，并有权获得报酬","correct":false}]', 'B', '此题考察软件著作权相关概念，建议掌握。根据《计算机软件保护条例》的第十五条。软件著作权属于自然人的，该自然人死亡后，在软件著作权的保护期内，软件著作权的继承人可以依照《中华人民共和国继承法》的有关规定，继承本条例第八条规定的除署名权以外的其他权利（不是各项权利）。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3320, 'question-system-analyst-2022-05-comprehensive-13211', '系统分析师', '法律法规', 2022, '2022年5月系统分析师综合知识-商标法', '韩国甲公司生产的平板电脑在其本国享有“Upad“注册商标专用权，但未在中国申请注册。中国乙公司生产的平板电脑也使用“Upad”商标，并享有中国注册商标专用权，但未在韩国申请注册。甲公司与乙公司生产的平板电脑都在中国市场上销售，此情形下，依据中国商标法， （ 问题1 ） 。', '[{"key":"A","text":"甲公司侵犯了乙公司的商标权","correct":true},{"key":"B","text":"甲公司未侵犯乙公司的商标权","correct":false},{"key":"C","text":"乙公司侵犯了甲公司的商标权","correct":false},{"key":"D","text":"甲公司与乙公司均未侵犯商标权","correct":false}]', 'A', '本题考查商标法相关概念，建议掌握。知识产权具有地域性的特征，只有按照一国法律获得承认和保护的知识产权在该国发生法律效力。目前知识产权的地域性仍然存在，如是否授予权利、如何保护权利，仍由各国内部法律来决定。在我国商标法中，未注册商标不得与已注册商标相同或近似，未经许可而使同种或类似商品使用相同或近似商标属于侵犯专用权的行为，需承担相应法律责任。题中甲公司的生产的平板电脑没有在中国申请注册，乙公司的“Upad”商标有中国注册商标专用权，所以甲公司侵犯了乙公司的商标权。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3321, 'question-system-analyst-2022-05-comprehensive-13208', '系统分析师', '法律法规', 2022, '2022年5月系统分析师综合知识-商标法', '以下商标注册申请，经审查，不能获准注册的是 （ 问题1 ） 。', '[{"key":"A","text":"青铜","correct":false},{"key":"B","text":"华山","correct":false},{"key":"C","text":"湖北","correct":true},{"key":"D","text":"麒麟","correct":false}]', 'C', '此题考察商标法相关概念，建议必须掌握。根据《中华人民共和国商标法》第十条规定，不能使用同国家名称、标志、特定地点或建筑物名称、外国国家名称或标志等相同或近似的标志作为商标；不能使用带有民族歧视、欺骗性、不良影响等特点的标志；不能使用县级以上行政区划的地名或公众知晓的外国地名作为商标，除非具有其他含义或作为集体商标、证明商标组成部分等情况。但是，已经注册的使用上述标志或地名的商标继续有效。', 1, 3, 'import', '2026-03-28 12:06:33', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3322, 'question-system-analyst-2022-05-comprehensive-13256', '系统分析师', '数据库系统', 2022, '2022年5月系统分析师综合知识-数据库设计', '在数据库设计的需求分析、概念结构设计、逻辑结构设计和物理结构设计的四个阶段中，基本E-R图是 （ 问题1 ） 。', '[{"key":"A","text":"需求分析阶段形成的文档，并作为概念结构设计阶段的设计依据","correct":false},{"key":"B","text":"逻辑结构设计阶段形成的文档，并作为概念结构设计阶段的设计依据","correct":false},{"key":"C","text":"概念结构设计阶段形成的文档，并作为逻辑结构设计阶段的设计依据","correct":true},{"key":"D","text":"概念结构设计阶段形成的文档，并作为物理设计阶段的设计依据","correct":false}]', 'C', '本题考察的是数据库设计中的设计产物，这是一道纯概念性的题目。在教材第五章5.5.1数据库设计阶段这一节明确了基于数据库系统生命周期的数据库设计可分为如下5 个阶段：规划、需求分析、概念设计、逻辑设计和物理设计。描述企业应用中的实体及联系，也就是在做ER图的建模。E -R 图是在概念设计的时候完成的。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3323, 'question-system-analyst-2022-05-comprehensive-13243', '系统分析师', '数据库系统', 2022, '2022年5月系统分析师综合知识-数据库设计', '在数据库的安全机制中，通过提供 （ 问题1 ） 供第三方开发人员调用进行数据更新，从而保证数据库的关系模式不被第三方所获取。', '[{"key":"A","text":"索引","correct":false},{"key":"B","text":"视图","correct":false},{"key":"C","text":"触发器","correct":false},{"key":"D","text":"存储过程","correct":true}]', 'D', '这是一道比较基础的题目。做过开发的同学一般都能理解索引、视图、触发器、存储过程的含义，因为索引、视图无法用于数据更新，因此可以直接排除。那么触发器和存储过程到底选哪个呢？虽然触发器可以作为更新机制，但是无法避免数据库的关系模式被第三方所获取，所以并不安全。而存储过程方式，可以定义一段代码，提供给用户程序来调用，避免了向第三方提供系统表结构的过程，体现了数据库的安全机制。故本题选D。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3324, 'question-system-analyst-2022-05-comprehensive-13238', '系统分析师', '数据库系统', 2022, '2022年5月系统分析师综合知识-数据库设计', '在数据库设计的需求分析、概念结构设计、逻辑结构设计和物理结构设计的四个阶段中，基本E-R图是 （ 问题1 ） 。', '[{"key":"A","text":"需求分析阶段形成的文档，并作为概念结构设计阶段的设计依据","correct":false},{"key":"B","text":"逻辑结构设计阶段形成的文档，并作为概念结构设计阶段的设计依据","correct":false},{"key":"C","text":"概念结构设计阶段形成的文档，并作为逻辑结构设计阶段的设计依据","correct":true},{"key":"D","text":"概念结构设计阶段形成的文档，并作为物理设计阶段的设计依据","correct":false}]', 'C', '本题考察的是数据库设计中的设计产物，这是一道纯概念性的题目。在教材第五章5.5.1数据库设计阶段这一节明确了基于数据库系统生命周期的数据库设计可分为如下5 个阶段：规划、需求分析、概念设计、逻辑设计和物理设计。描述企业应用中的实体及联系，也就是在做ER图的建模。E -R 图是在概念设计的时候完成的。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3325, 'question-system-analyst-2022-05-comprehensive-13242', '系统分析师', '数据库', 2022, '2022年5月系统分析师综合知识-数据库理论', '给定关系模式R（U，F），U={A₁，A₂，A₃，A4}， F={A₁→A₂A₃， A₂A₃→A4}，那么在关系R中 （ 问题1 ） 。以下说法错误的是 （ 问题2 ） 。', '[{"key":"A","text":"根据F中“A₁→A₂A₃”，可以得出“A₁→A₂”","correct":false},{"key":"B","text":"根据F中“A₁→A₂A₃”，可以得出“A₁→A₃”","correct":false},{"key":"C","text":"根据F中“A₂A₃→A4”，可以得出“A₂→A4，A₃→A4”","correct":true},{"key":"D","text":"根据F中“A₁→A₂A₃，A₂A₃→A4”，可以得出“A₁→A4”","correct":false}]', 'C', '第一空考查候选关键字的分析，认为是必会题送分题，必须掌握。针对这种题目，给定一个关系模式，如何求取候选键呢？就是函数依赖图（有向图）！从入度为0的节点开始，找出图中一个节点或者一个节点组合，能够遍历完整个图，就是候选键。根据题意你可以自行可绘制出函数依赖图（其他题目已经讲过多次），可以看出候选键为A1，因此本题第一空选择A选项。

本题第二空考查的是Armstrong公理体系的应用，这个比较偏门，它包含三个公理和两个推导公式。但是你就算不知道这个定理，凭借开发的经验，逐个带入，也知道 根据F中“A₂A₃→A4”，可以得出“A₂→A4，A₃→A4” 是错误的。所以选C选项。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3326, 'question-system-analyst-2022-05-comprehensive-13241', '系统分析师', '数据库', 2022, '2022年5月系统分析师综合知识-数据库理论', '给定关系模式R（U，F），U={A₁，A₂，A₃，A4}， F={A₁→A₂A₃， A₂A₃→A4}，那么在关系R中 （ 问题1 ） 。以下说法错误的是 （ 问题2 ） 。', '[{"key":"A","text":"有1个候选关键字A1","correct":true},{"key":"B","text":"有1个候选关键字A2A3","correct":false},{"key":"C","text":"有2个候选关键字A2和A3","correct":false},{"key":"D","text":"有2个候选关键字A1和A2A3","correct":false}]', 'A', '第一空考查候选关键字的分析，认为是必会题送分题，必须掌握。针对这种题目，给定一个关系模式，如何求取候选键呢？就是函数依赖图（有向图）！从入度为0的节点开始，找出图中一个节点或者一个节点组合，能够遍历完整个图，就是候选键。根据题意你可以自行可绘制出函数依赖图（其他题目已经讲过多次），可以看出候选键为A1，因此本题第一空选择A选项。

本题第二空考查的是Armstrong公理体系的应用，这个比较偏门，它包含三个公理和两个推导公式。但是你就算不知道这个定理，凭借开发的经验，逐个带入，也知道 根据F中“A₂A₃→A4”，可以得出“A₂→A4，A₃→A4” 是错误的。所以选C选项。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3327, 'question-system-analyst-2022-05-comprehensive-13240', '系统分析师', '数据库', 2022, '2022年5月系统分析师综合知识-数据库理论', '给定关系 R(A,B,C,D,E) 和关系 S(D,E,F,G)，对其进行自然连接运算 R⋈S 后其结果集的属性列为 （ 问题1 ） 。', '[{"key":"A","text":"R.A，R.B，R.C，R.D，R.E，S.D，S.E","correct":false},{"key":"B","text":"R.A，R.B，R.C，R.D，R.E，S.F，S.G","correct":true},{"key":"C","text":"R.A，R.B，R.C，R.D，R.E，S.E，S.F","correct":false},{"key":"D","text":"R.A，R.B，R.C，R.D，R.E，S.D，S.E，S.F，S.G","correct":false}]', 'B', '这里蕴含了两个细节。第一个是自然连接是什么？第二个是自然连接的符号是什么。学过数据库理论的同学都知道自然连接可看作是在广义笛卡尔积R×S中选出同名属性上符合相等条件元组，再进行投影，去掉重复的同名属性，组成新的关系，符号是⋈。笛卡尔乘积的符号是×。搞懂了这个这道题目就可以判定为B选项。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3328, 'question-system-analyst-2022-05-comprehensive-13239', '系统分析师', '数据库系统', 2022, '2022年5月系统分析师综合知识-数据库理论', '某高校信息系统采用分布式数据库系统，该系统中“当某一场地故障时，系统可以使用其它场地上的副本而不至于使整个系统瘫痪”和“数据在不同场地上的存储”分别称为分布式数据库的 （ 问题1 ） 。', '[{"key":"A","text":"共享性和分布性","correct":false},{"key":"B","text":"自治性和分布性","correct":false},{"key":"C","text":"自治性和可用性","correct":false},{"key":"D","text":"可用性和分布性","correct":true}]', 'D', '此题考察分布式数据库的相关概念，属于超纲题，但是仍然建议掌握。分布式数据库系统是由一组数据组成的，这组数据分布在计算机网络的不同计算机上，网络中的每个节点具有独立处理的能力，能够执行局部应用和全局应用。分布式数据库系统具有数据独立性，集中与自治共享结合的控制结构，适当增加数据冗余度，以及全局的一致性、可串行性和可恢复性等特点。题目描述了分布式数据库系统具有场地自治和可用性，以及数据分布性的特点，因此选择D选项。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3329, 'question-system-analyst-2022-05-comprehensive-13255', '系统分析师', '数学与经济管理', 2022, '2022年5月系统分析师综合知识-网络与最大流量', '某地天然气输送管线网络图如下，每段管线旁的数字表示输气能力（单位：万立方米/小时）。根据该图，从源S到目的地T的最大输气能力为 （ 问题1 ） 万立方米/小时。', '[{"key":"A","text":"4","correct":false},{"key":"B","text":"8","correct":false},{"key":"C","text":"9","correct":true},{"key":"D","text":"10","correct":false}]', 'C', '此题网络与最大流量，出自书本 2.8.3 章节，建议可以掌握。本题要求从结点1到结点6的最大流量，其实就是把从结点1到结点6所有的路径找出来，然后把每条路径的流量进行累加。建议搞懂。此题通过分析可以知道，总共抽取流量：3+2+2+1+1=9，最大输出能力为9万立方米/小时。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3330, 'question-system-analyst-2022-05-comprehensive-13250', '系统分析师', '数学与经济管理', 2022, '2022年5月系统分析师综合知识-线性规划', '各种线性规划模型都可以将其标准化。线性规划模型标准形式的特点不包括 （ 问题1 ） 。', '[{"key":"A","text":"目标函数达到最大化（或最小化）","correct":true},{"key":"B","text":"约束条件都是线性等式","correct":false},{"key":"C","text":"约束条件中的常数系数均为非负","correct":false},{"key":"D","text":"所有的决策变量均为非负","correct":false}]', 'A', '此题考察线性规划的概念，不是重点，建议了解即可。线性规划的标准型是线性规划模型的标准形式。其主要特征为（1）求目标函数的最大值（目标函数是求最大值，而不是最小值）。（2）约束条件中变量满足线性方程组与非负性两部分（约束条件中所有x是大于0的）。（3）方程组中右端常数项皆非负（常数项b是非负的）。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3331, 'question-system-analyst-2022-05-comprehensive-13254', '系统分析师', '数学与经济管理', 2022, '2022年5月系统分析师综合知识-最小生成树', '某乡有7个小山村A~G，村与村之间原有小路可加宽修建公路的线路如下图所示（路边的数字表示路长的公里数）。为实现村村通公路，修建公路总长至少 （ 问题1 ） 公里。若在 （ 问题2 ） 村新建一所中学，则可以使人们从离它最远的村到该校所走的优化路程最短。', '[{"key":"A","text":"A","correct":false},{"key":"B","text":"C","correct":false},{"key":"C","text":"D","correct":false},{"key":"D","text":"E","correct":true}]', 'D', '此题考察最小生成树算法，出自书本2.8.1，建议必须掌握。该题可用图论中的最小生成树算法来求解。求带权连通无向图的最小生成树的算法有普里姆（Prim ) 算法（找点和当前集合的最小距离纳入集合）和 克鲁斯卡尔（Kruskal) 算法（边按长短排序然后凑，不形成闭环即可），实际计算建议釆用克鲁斯卡尔算法。你可以自行百度。例如，总成本最低的方案之一如下所示。综上可知，修建公路总长至少13.8公里。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3332, 'question-system-analyst-2022-05-comprehensive-13253', '系统分析师', '数学与经济管理', 2022, '2022年5月系统分析师综合知识-最小生成树', '某乡有7个小山村A~G，村与村之间原有小路可加宽修建公路的线路如下图所示（路边的数字表示路长的公里数）。为实现村村通公路，修建公路总长至少 （ 问题1 ） 公里。若在 （ 问题2 ） 村新建一所中学，则可以使人们从离它最远的村到该校所走的优化路程最短。', '[{"key":"A","text":"13.8","correct":true},{"key":"B","text":"14.3","correct":false},{"key":"C","text":"14.8","correct":false},{"key":"D","text":"15.3","correct":false}]', 'A', '此题考察最小生成树算法，出自书本2.8.1，建议必须掌握。该题可用图论中的最小生成树算法来求解。求带权连通无向图的最小生成树的算法有普里姆（Prim ) 算法（找点和当前集合的最小距离纳入集合）和 克鲁斯卡尔（Kruskal) 算法（边按长短排序然后凑，不形成闭环即可），实际计算建议釆用克鲁斯卡尔算法。你可以自行百度。例如，总成本最低的方案之一如下所示。综上可知，修建公路总长至少13.8公里。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3333, 'question-system-analyst-2022-05-comprehensive-13244', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-死锁问题', '某系统中有5个并发进程竞争资源R。假设每个进程都需要3个R，那么最少需要有 （ 问题1 ） 个R，才能保证系统不会发生死锁。', '[{"key":"A","text":"10","correct":false},{"key":"B","text":"11","correct":true},{"key":"C","text":"12","correct":false},{"key":"D","text":"13","correct":false}]', 'B', '此题考察死锁问题，出自书本3.2.3章节，建议必须掌握。系统不会发生死锁的条件有互斥条件——至少一个资源必须处于非共享模式下，即在一段时间内只允许一个进程使用该资源。不可抢占资源——已分配的资源不能被抢占，只能由占用该资源的进程显式地释放。占有和等待条件——进程在请求其他资源时必须持有至少一个资源，并等待其他进程释放它占有的资源。循环等待条件——存在一个进程链，每个进程都在等待链中的下一个进程所拥有的资源。对于此题来说，只要满足系统资源总数大于 进程数*（每个进程所需资源数-1）+1 即可。也就是说系统资源总数至少要等于 11 才能让系统避免死锁，本题选择B选项。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3334, 'question-system-analyst-2022-05-comprehensive-13246', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-文件系统', '某文件管理系统在磁盘上建立了位示图（bitmap），记录磁盘的使用情况。若磁盘上物理块的编号依次为：0 、1、2、……；系统中的字长为32位，字的编号依次为： 0 、1、2，字中的一位对应文件存储器上的一个物理块，取值0表示该物理块空闲，取值1表示该物理块占用，如下图所示。

假设操作系统将256号物理块分配给某文件，那么该物理块的使用情况在位示图中编号为 （ 问题1 ） 的字中描述；系统应该将 （ 问题2 ） 。', '[{"key":"A","text":"该字的位号32的位置“1”","correct":false},{"key":"B","text":"该字的位号0的位置“1”","correct":true},{"key":"C","text":"该字的位号32的位置“0”","correct":false},{"key":"D","text":"该字的位号0的位置“0”","correct":false}]', 'B', '根据题意系统中字长为32位，可记录32个物理块的使用情况。

256号物理块从0开始编号，在第256+1=257个位置，每32个物理块占用1个字，则257个物理块占用情况如下：

257/32=8…1

也就是需要放置在第9个字的第1个位置，字的编号和位的编号都从0开始，此时第9个字的第1个位置对应字的编号为8，位的编号为0。

将对应位置分配出去的操作为：将对应位置置为“1” 。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3335, 'question-system-analyst-2022-05-comprehensive-13245', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-文件系统', '某文件管理系统在磁盘上建立了位示图（bitmap），记录磁盘的使用情况。若磁盘上物理块的编号依次为：0 、1、2、……；系统中的字长为32位，字的编号依次为： 0 、1、2，字中的一位对应文件存储器上的一个物理块，取值0表示该物理块空闲，取值1表示该物理块占用，如下图所示。

假设操作系统将256号物理块分配给某文件，那么该物理块的使用情况在位示图中编号为 （ 问题1 ） 的字中描述；系统应该将 （ 问题2 ） 。', '[{"key":"A","text":"5","correct":false},{"key":"B","text":"6","correct":false},{"key":"C","text":"7","correct":false},{"key":"D","text":"8","correct":true}]', 'D', '此题考察存储管理中，位示图相关概念，出自书本3.4.2，建议必须掌握。根据题意系统中字长为32位，可记录32个物理块的使用情况。256号物理块从0开始编号，在第256+1=257个位置，每32个物理块占用1个字，则257个物理块占用情况为 257/32=8…1

由于字的编号和位的编号都从0开始，此时第9个字的第1个位置对应字的编号为8，位的编号为0。。一般把“1”作为盘块已分配的标记，把“0”作为空闲标志。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3336, 'question-system-analyst-2022-05-comprehensive-13249', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-信号量', '进程P1、P2、P3、P4、P5和P6的前趋图如下所示：

若用PV操作控制进程P1、P2、P3、P4、P5和P6并发执行的过程，则需要设置7个信号量S1、S2、S3、S4、S5、S6和S7， 且信号量S1~S7的初值都等于零。如下的进程执行图中，a和b处应分别填写 （ 问题1 ） ；c和 d处应分别填写 （ 问题2 ） ，e和f处应分别填写 （ 问题3 ） 。', '[{"key":"A","text":"P（S6）和V（S7）","correct":false},{"key":"B","text":"V（S6）和P（S6）","correct":false},{"key":"C","text":"V（S7）和P（S7）","correct":true},{"key":"D","text":"V（S6）和V（S7）","correct":false}]', 'C', '此题是信号量与前趋图相结合的一道题目，出自书本3.2.2章节，考的频率非常之高，建议必须掌握。前趋图的先后关系代表了后者必须等待前者执行完才能做一下步操作，此时前者结束时发出V操作释放资源，后者发出P操作请求资源进行等待。根据此判断原则可知答案。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3337, 'question-system-analyst-2022-05-comprehensive-13248', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-信号量', '进程P1、P2、P3、P4、P5和P6的前趋图如下所示：

若用PV操作控制进程P1、P2、P3、P4、P5和P6并发执行的过程，则需要设置7个信号量S1、S2、S3、S4、S5、S6和S7， 且信号量S1~S7的初值都等于零。如下的进程执行图中，a和b处应分别填写 （ 问题1 ） ；c和 d处应分别填写 （ 问题2 ） ，e和f处应分别填写 （ 问题3 ） 。', '[{"key":"A","text":"V（S4）和P （S3）P（S4）","correct":false},{"key":"B","text":"P（S4）和P （S3）P（S4）","correct":false},{"key":"C","text":"P（S3）和V （S4）V（S5）","correct":false},{"key":"D","text":"V（S4）V（S5）和P（S3）P（S4）","correct":true}]', 'D', '此题是信号量与前趋图相结合的一道题目，出自书本3.2.2章节，考的频率非常之高，建议必须掌握。前趋图的先后关系代表了后者必须等待前者执行完才能做一下步操作，此时前者结束时发出V操作释放资源，后者发出P操作请求资源进行等待。根据此判断原则可知答案。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3338, 'question-system-analyst-2022-05-comprehensive-13247', '系统分析师', '计算机基础', 2022, '2022年5月系统分析师综合知识-信号量', '进程P1、P2、P3、P4、P5和P6的前趋图如下所示：

若用PV操作控制进程P1、P2、P3、P4、P5和P6并发执行的过程，则需要设置7个信号量S1、S2、S3、S4、S5、S6和S7， 且信号量S1~S7的初值都等于零。如下的进程执行图中，a和b处应分别填写 （ 问题1 ） ；c和 d处应分别填写 （ 问题2 ） ，e和f处应分别填写 （ 问题3 ） 。', '[{"key":"A","text":"P（S1）和V（S2）V（S3）","correct":true},{"key":"B","text":"V（S1）和P（S2）V（S3）","correct":false},{"key":"C","text":"P（S1）和P（S2）V（S3）","correct":false},{"key":"D","text":"V（S1）和V（S2）V（S3）","correct":false}]', 'A', '此题是信号量与前趋图相结合的一道题目，出自书本3.2.2章节，考的频率非常之高，建议必须掌握。前趋图的先后关系代表了后者必须等待前者执行完才能做一下步操作，此时前者结束时发出V操作释放资源，后者发出P操作请求资源进行等待。根据此判断原则可知答案。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3339, 'question-system-analyst-2022-05-comprehensive-13215', '系统分析师', '嵌入式系统', 2022, '2022年5月系统分析师综合知识-硬件知识', '由于处理器芯片在不同领域应用时，需要考虑对环境的适应性。通常，我们把芯片分为民用级、工业级和军用级。 （ 问题1 ） 分别是民用级、工业级和军用级芯片的标准工作温度范围。', '[{"key":"A","text":"-10℃ ~+70℃ 、-40℃~+80℃ 、-50℃+150℃","correct":false},{"key":"B","text":"0℃~+70℃、-30℃~+85℃、-60℃~+150℃","correct":false},{"key":"C","text":"0℃~+70℃、-40℃~+85℃、-55℃~+150℃","correct":true},{"key":"D","text":"-10℃~+60℃、-40℃~+90℃、 -55℃~+150℃","correct":false}]', 'C', '此题考查的是嵌入式微处理器的分级温度特点，属于超纲题，建议了解即可。嵌入式微处理器主要用于处理相关任务，因此在选择处理器芯片时，要根据不同使用环境选择不同级别的芯片，其主要因素是芯片可适应的工作环境温度。一般来说，芯片分为民用级、工业级和军用级，它们的工作温度范围分别为0~70℃、-40~85℃和-55~150℃。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3340, 'question-system-analyst-2022-05-comprehensive-13216', '系统分析师', '嵌入式系统', 2022, '2022年5月系统分析师综合知识-嵌入式系统', '嵌入式实时系统存在许多调度算法。如果调度程序根据任务的紧急程度确定该任务的优先级，任务紧急程度高，被赋予的优先级就高，可被优先执行。这种调度算法称之为 （ 问题1 ） 。', '[{"key":"A","text":"最早截止时间优先（Earliest Deadline First, EDF）算法","correct":false},{"key":"B","text":"最低松弛度优先（Least Laxity First, LLF）算法","correct":true},{"key":"C","text":"单调速率调度（Rate Monotonic Scheduling, RMS）算法","correct":false},{"key":"D","text":"抢占式优先级调度（Preemptive Priority Scheduling, PPS）算法","correct":false}]', 'B', '此题考查的是嵌入式实时系统调度算法，书上原话 556 页，建议了解即可。嵌入式实时系统常见的调度算法，包括最早截止期、最晚截止期、LLF和优先级调度算法。其中，最低松弛度优先（Least Laxity First，LLF) 算法是根据任务紧急（或松弛）的程度，来确定任务的优先级。任务的紧急程度愈高，该任务被赋予的优先级就愈高，以使之优先执行。松弛度（又叫富裕度）即进程的富裕时间，例如，一个任务在达到200m s时必须完成，而它本身所需的运行时间就有100ms,因此，调度程序必须在100m s之前调度执行，该任务的紧急程度（松弛程度）为100ms。 在实现该算法时首先计算各个进程的松弛度，组织一个按松弛度排序的实时任务就绪队列，松弛度最低的任务排在队列最前面，调度程序总是选择就绪队列中的队首任务，即松弛度最少的进程执行。该算法主要用于可剥夺调度方式中。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3341, 'question-system-analyst-2022-05-comprehensive-13214', '系统分析师', '嵌入式系统', 2022, '2022年5月系统分析师综合知识-嵌入式系统', '嵌入式软件开发方法与传统软件开发方法存在较大差异， （ 问题1 ） 的说法对嵌入式软件开发而言是错误的。', '[{"key":"A","text":"嵌入式软件开发的结果通常需要固化在目标系统的储存器或处理器内部储存器资源中","correct":false},{"key":"B","text":"嵌入式软件的开发一般需要专门的开发工具、目标系统和测试设备","correct":false},{"key":"C","text":"嵌入式软件对安全性和可靠性的要求较高","correct":false},{"key":"D","text":"嵌入式软件开发不用考虑代码的规模","correct":true}]', 'D', '此题考察嵌入式软件开发方法的相关知识，属于超纲题，建议了解即可，此题难度不大，通过常识也可以知道 D 是错误的。嵌入式软件开发与传统软件开发方法有较大差异，包括使用专门工具生成二进制代码后运行在目标机器、强调软/硬件协同工作、结果需要固化在目标系统、需要专门工具和测试设备、对实时性、安全性和可靠性要求更高，以及需要考虑代码规模和满足特定领域的审定要求。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3342, 'question-system-analyst-2022-05-comprehensive-13213', '系统分析师', '嵌入式系统', 2022, '2022年5月系统分析师综合知识-嵌入式系统', '嵌入式系统已被广泛应用到各行各业。嵌入式系统是一个内置于设备中，对设备的各种传感器进行管理与控制的系统。通常，根据系统对时间的敏感程度可将嵌入式系统划分为 （ 问题1 ） 两种，而实时系统又可分为强实时（Hard Real-Time）系统和弱实时（Weak Real-Time）系统；如果从安全性要求看，嵌入式系统还可分为 （ 问题2 ） 。', '[{"key":"A","text":"高可靠系统和高安全系统","correct":false},{"key":"B","text":"实时系统和强实时系统","correct":false},{"key":"C","text":"安全攸关系统和非安全攸关系统","correct":true},{"key":"D","text":"网络系统和分布式系统","correct":false}]', 'C', '此题考查的是嵌入式系统分类，属于超纲题，建议了解即可。根据系统对时间的敏感程度可将嵌入式系统划分为嵌入式系统、嵌入式实时系统、强实时系统、弱实时系统。从安全性要求看，嵌入式系统还可分为安全攸关系统、非安全攸关系统。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3343, 'question-system-analyst-2022-05-comprehensive-13212', '系统分析师', '嵌入式系统', 2022, '2022年5月系统分析师综合知识-嵌入式系统', '嵌入式系统已被广泛应用到各行各业。嵌入式系统是一个内置于设备中，对设备的各种传感器进行管理与控制的系统。通常，根据系统对时间的敏感程度可将嵌入式系统划分为 （ 问题1 ） 两种，而实时系统又可分为强实时（Hard Real-Time）系统和弱实时（Weak Real-Time）系统；如果从安全性要求看，嵌入式系统还可分为 （ 问题2 ） 。', '[{"key":"A","text":"嵌入式系统和嵌入式实时系统","correct":true},{"key":"B","text":"控制系统和业务系统","correct":false},{"key":"C","text":"安全攸关系统和非安全攸关系统","correct":false},{"key":"D","text":"CPS系统和非CPS系统","correct":false}]', 'A', '此题考查的是嵌入式系统分类，属于超纲题，建议了解即可。根据系统对时间的敏感程度可将嵌入式系统划分为嵌入式系统、嵌入式实时系统、强实时系统、弱实时系统。从安全性要求看，嵌入式系统还可分为安全攸关系统、非安全攸关系统。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3344, 'question-system-analyst-2022-05-comprehensive-13223', '系统分析师', '企业信息化战略与实施', 2022, '2022年5月系统分析师综合知识-企业信息系统', '智能制造系统架构从生命周期、系统层级和智能特征3个维度对智能制造所涉及的活动、装备、特征等内容进行描述，主要用于明确智能制造的 （ 问题1 ） ，指导国家智能制造标准体系建设。其中，系统层级是对与企业生产活动相关的组织结构的层级划分，包括 （ 问题2 ） 。', '[{"key":"A","text":"设备层、单元层、车间层、企业层和应用层","correct":false},{"key":"B","text":"设备层、单元层、传输层、企业层和应用层","correct":false},{"key":"C","text":"设备层、单元层、传输层、企业层和协同层","correct":false},{"key":"D","text":"设备层、单元层、车间层、企业层和协同层","correct":true}]', 'D', '此题考察智能制造的相关知识，属于超纲题，建议了解即可。智能制造系统架构从生命周期、系统层级和智能特征等3个维度对智能制造所涉及的要素、装备、活动等内容进行描述，主要用于明确智能制造的标准化对象和范围。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3345, 'question-system-analyst-2022-05-comprehensive-13222', '系统分析师', '企业信息化战略与实施', 2022, '2022年5月系统分析师综合知识-企业信息系统', '智能制造系统架构从生命周期、系统层级和智能特征3个维度对智能制造所涉及的活动、装备、特征等内容进行描述，主要用于明确智能制造的 （ 问题1 ） ，指导国家智能制造标准体系建设。其中，系统层级是对与企业生产活动相关的组织结构的层级划分，包括 （ 问题2 ） 。', '[{"key":"A","text":"标准化需求、业务和对象","correct":false},{"key":"B","text":"标准化需求、对象和范围","correct":true},{"key":"C","text":"标准化需求、业务和流程","correct":false},{"key":"D","text":"标准化需求、流程和范围","correct":false}]', 'B', '此题考察智能制造的相关知识，属于超纲题，建议了解即可。智能制造系统架构从生命周期、系统层级和智能特征等3个维度对智能制造所涉及的要素、装备、活动等内容进行描述，主要用于明确智能制造的标准化对象和范围。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3346, 'question-system-analyst-2022-05-comprehensive-13235', '系统分析师', '企业信息化战略与实施', 2022, '2022年5月系统分析师综合知识-企业信息化规划', '在企业信息化中， （ 问题1 ） 的主要方法有业务与IT整合和企业IT架构构建。下面关于上述两种方法的说法中，不正确的是 （ 问题2 ） 。', '[{"key":"A","text":"业务与IT整合和企业IT架构两种方法不存在任何领域的重叠","correct":true},{"key":"B","text":"业务与IT整合是一种以业务为导向的、全面的IT管理咨询实施方法论","correct":false},{"key":"C","text":"企业IT架构帮助企业制订IT战略，并对其投资决策进行指导","correct":false},{"key":"D","text":"企业IT架构适用于现有信息系统和IT基础架构不一致、不兼容和缺乏统一的整体管理的企业","correct":false}]', 'A', '企业战略与信息化战略集成的主要方法有BITA（Business-IT Alignment，业务与IT整合）和EITA（Enterprise IT Architecture，企业IT架构）。

（1）业务与IT整合。BITA是一种以业务为导向的、全面的IT管理咨询实施方法论。从制订企业战略、建立（或改进）企业组织结构和业务流程，到进行IT管理和制订过渡计划（transition plan），使IT能够更好地为企业战略和目标服务。BITA适用于信息系统不能满足当前管理中的业务需要，业务和IT之间总是有不一致的地方。BITA的主要步骤是：评估和分析企业当前业务和IT不一致的领域，整理出企业的业务远景和未来战略，建立业务模型，提出达到未来目标的转变过程建议和初步计划，以及执行计划。

（2）企业IT架构。EITA分析企业战略，帮助企业制订IT战略，并对其投资决策进行指导。在技术、信息系统、信息、IT组织和IT流程方面，帮助企业建立IT的原则规范、模式和标准，指出IT需要改进的方面并帮助制订行动计划。EITA适用于现有信息系统和IT基础架构不一致、不兼容和缺乏统一的整体管理的企业。

根据以上介绍可知，BITA和EITA有相同之处，甚至在某些领域有重叠。在企业信息化实践中，需要根据实际情况，选择其中的一种方法，或者结合使用BITA和EITA方法进行实施。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3347, 'question-system-analyst-2022-05-comprehensive-13234', '系统分析师', '企业信息化战略与实施', 2022, '2022年5月系统分析师综合知识-企业信息化规划', '在企业信息化中， （ 问题1 ） 的主要方法有业务与IT整合和企业IT架构构建。下面关于上述两种方法的说法中，不正确的是 （ 问题2 ） 。', '[{"key":"A","text":"信息架构继承","correct":false},{"key":"B","text":"企业战略与信息化战略集成","correct":true},{"key":"C","text":"信息化规划与业务整合","correct":false},{"key":"D","text":"信息化规划与企业战略规划","correct":false}]', 'B', '此题考察企业战略和信息化战略的集成方式，属于超纲题，建议了解即可。BITA（业务与 IT 整合） 以业务为导向，可以帮助企业进行全面的IT管理咨询，整合IT和业务服务企业战略。EITA（企业 IT 架构） 则分析企业战略，提供建议，帮助企业制定行动计划。BITA 适用于业务和 IT 不一致的企业，而 EITA 适用于现有信息系统和IT基础架构不一致、不兼容和缺乏统一整体管理的企业。企业根据自身需求选择合适的方法，将战略和信息化战略相互融合，为企业的持续发展提供支撑。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3348, 'question-system-analyst-2022-05-comprehensive-13233', '系统分析师', '企业信息化战略与实施', 2022, '2022年5月系统分析师综合知识-企业信息化规划', '信息化规划与企业战略规划总是互相影响、互相促进的。当财务部门提出财务电算化的需求，生产部门提出库房管理的需求时，IT部门根据不同部门的需求分别独立实施，以此形成一个完全基于企业组织与业务流程的信息系统结构， 其中各个信息系统分别对应于特定部门或特定业务流程。这表明 （ 问题1 ） 。', '[{"key":"A","text":"企业处在信息化的初级阶段","correct":true},{"key":"B","text":"企业处在信息化的中级阶段","correct":false},{"key":"C","text":"企业处在信息化的高级阶段","correct":false},{"key":"D","text":"企业处在信息化的完成阶段","correct":false}]', 'A', '此题考察企业信息化规划的相关概念，出自书本 7.2 章节，建议了解即可。初级阶段是当企业处在信息化的初级阶段时，业务部门根据现有的业务流程或管理需要，直接提出信息化需求，IT部门按照需求实施。中级阶段是根据企业整体战略和优化的组织结构和流程，各部门提出需求，IT 部门独立实施。高级阶段是企业通盘考虑各部门需求，制订整体信息化战略，统一规划，分步实施。信息系统结构由企业信息化战略统一指导，并与优化后的组织结构和业务流程相适应。该企业信息化还停留在根据现有的业务流程或管理需要，直接提出信息化需求，没有整体战略规划，这属于信息化初级阶段。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3349, 'question-system-analyst-2022-05-comprehensive-13221', '系统分析师', '企业信息化战略与实施', 2022, '2022年5月系统分析师综合知识-企业信息化规划', 'TOGAF 框架是一个多视图的体系结构，它由企业的业务架构、信息架构、应用架构和技术架构共同构成。企业信息架构是将企业业务实体抽象成为信息对象，将企业的业务运作模式抽象为信息对象的属性和方法，建立面向对象的企业信息模型。企业信息架构实现了从 （ 问题1 ） 。

①业务模式向信息模型的转变

②业务需求向信息功能的映射

③企业基础数据向企业信息的抽象

④业务逻辑向功能逻辑的演化', '[{"key":"A","text":"①②③","correct":true},{"key":"B","text":"①②④","correct":false},{"key":"C","text":"①③④","correct":false},{"key":"D","text":"②③④","correct":false}]', 'A', '此题考察企业信息架构相关概念，属于超纲题，建议了解即可。企业信息架构是将企业业务实体抽象成为信息对象，将企业的业务运作模式抽象成为信息对象的属性和方法，建立面向对象的企业信息模型。企业信息架构实现从业务模式向信息模型的转变，业务需求向信息功能的映射，企业基础数据向企业信息的抽象。企业信息架构对企业业务进行建模，它能独立于技术的发展和变化，并能帮助项目中业务人员和技术人员之间的沟通。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3350, 'question-system-analyst-2022-05-comprehensive-13217', '系统分析师', '企业信息化战略与实施', 2022, '2022年5月系统分析师综合知识-企业信息化规划', '企业信息化工程是将 （ 问题1 ） 相结合，改善企业的经营、管理、产品开发和生产等各个环节，提高生产效率、产品质量和企业的创新能力，从而实现产品设计制造和企业管理的信息化、生产过程的智能化、制造装备的数控化以及咨询服务的网络化，全面提高我国企业的竞争力。', '[{"key":"A","text":"信息技术、自动化技术、现代管理技术、制造技术","correct":true},{"key":"B","text":"信息技术、自动化技术、现代管理技术、建模技术","correct":false},{"key":"C","text":"信息技术、测试技术、现代管理技术、制造技术","correct":false},{"key":"D","text":"需求分析技术、建模技术、测试技术、现代管理技术","correct":false}]', 'A', '此题考察企业信息化工程相关概念，属于超纲题，建议了解即可。企业信息化工程是将信息技术、自动化技术、现代管理技术、制造技术相结合，改善企业的经营、管理、产品开发和生产等各个环节，提高生产效率、产品质量和企业的创新能力。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3351, 'question-system-analyst-2022-05-comprehensive-13252', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-项目管理', '某项目有8个作业A~H，每个作业的紧前作业、所需天数和所需人数见下表。由于整个项目团队总共只有10人，各个作业都必须连续进行，中途不能停止，因此需要适当安排施工方案，使该项目能尽快在 （ 问题1 ） 内完工。在该方案中，作业A应安排在 （ 问题2 ） 内进行。', '[{"key":"A","text":"第1~5天","correct":false},{"key":"B","text":"第3~7天","correct":false},{"key":"C","text":"第5~9天","correct":false},{"key":"D","text":"第8~12天","correct":true}]', 'D', '此题考察的其实是项目管理——进度管理中的单代号网络图，但是此题又和人员分配放在一起，变得更加复杂了，建议时间充裕的同学可以看看。首先第一问，关键是6标志图的绘制，得到关键路径为此时关键路径为C-F-G-H，项目工期至少需要11天。再根据题干要求分析，项目团队一共只有10人，此时项目受到人员限制，需要调整。分析发现，A、C、E、F这4个活动因为人员不足所以不可以同时并行只能顺序执行。根据逻辑关系可知C活动必须在F活动之前、B活动必须在E活动之前、D活动和F活动必须在G活动之前、E活动和G活动必须在H活动之前，A活动没有限制可以放在最后考虑。因为逻辑关系限定，可以先考虑C活动和F活动，再考虑E活动，然后将其他活动并行安排在这4个活动的时间内，得到如下的安排表：

综上可知，项目最快能在12天完工，此时A活动安排在第8~12天。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3352, 'question-system-analyst-2022-05-comprehensive-13251', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-项目管理', '某项目有8个作业A~H，每个作业的紧前作业、所需天数和所需人数见下表。由于整个项目团队总共只有10人，各个作业都必须连续进行，中途不能停止，因此需要适当安排施工方案，使该项目能尽快在 （ 问题1 ） 内完工。在该方案中，作业A应安排在 （ 问题2 ） 内进行。', '[{"key":"A","text":"10","correct":false},{"key":"B","text":"11","correct":false},{"key":"C","text":"12","correct":true},{"key":"D","text":"13","correct":false}]', 'C', '此题考察的其实是项目管理——进度管理中的单代号网络图，但是此题又和人员分配放在一起，变得更加复杂了，建议时间充裕的同学可以看看。首先第一问，关键是6标志图的绘制，得到关键路径为此时关键路径为C-F-G-H，项目工期至少需要11天。再根据题干要求分析，项目团队一共只有10人，此时项目受到人员限制，需要调整。分析发现，A、C、E、F这4个活动因为人员不足所以不可以同时并行只能顺序执行。根据逻辑关系可知C活动必须在F活动之前、B活动必须在E活动之前、D活动和F活动必须在G活动之前、E活动和G活动必须在H活动之前，A活动没有限制可以放在最后考虑。因为逻辑关系限定，可以先考虑C活动和F活动，再考虑E活动，然后将其他活动并行安排在这4个活动的时间内，得到如下的安排表：

综上可知，项目最快能在12天完工，此时A活动安排在第8~12天。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3353, 'question-system-analyst-2022-05-comprehensive-13220', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-软件架构设计', '相比传统 SOA 的服务实现方式，微服务更具有灵活性、可实施性以及可扩展性，其强调的是一种 （ 问题1 ） 的软件架构模式。', '[{"key":"A","text":"联合测试、独立部署、独立运行","correct":false},{"key":"B","text":"联合测试、独立部署、集中运行","correct":false},{"key":"C","text":"独立测试、独立部署、独立运行","correct":true},{"key":"D","text":"独立测试、独立部署、集中运行","correct":false}]', 'C', '此题考察微服务的相关观念，属于超纲题，但是建议掌握。微服务强调的是一种独立开发、独立测试、独立部署、独立运行的高度自治的架构模式，也是一种更灵活、更开发、更松散的演进式架构。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3354, 'question-system-analyst-2022-05-comprehensive-13219', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-软件架构设计', '云计算可以按需提供弹性资源，它的体系结构由5部分组成。其中， （ 问题1 ） 为用户提供对资源层的各项云计算服务的封装，帮助用户构建所需的应用。', '[{"key":"A","text":"应用层","correct":false},{"key":"B","text":"平台层","correct":true},{"key":"C","text":"用户访问层","correct":false},{"key":"D","text":"管理层","correct":false}]', 'B', '此题考察云计算的相关概念，属于超纲题，但是建议掌握。云计算可以提供弹性资源，其体系结构由五个部分组成资源层、平台层、应用层、用户访问层和管理层。资源层提供虚拟化资源，平台层为用户提供资源层的封装，应用层提供软件服务，用户访问层方便用户使用各种支撑服务，管理层提供对所有层次云计算服务的管理功能。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3355, 'question-system-analyst-2022-05-comprehensive-13201', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-软件架构设计', '模型驱动的体系结构是一种关注模型的软件设计和实现方法，使用了UML模型的子集描述系统，创建不同抽象层次上的模型，其中不包括 （ 问题1 ） 。', '[{"key":"A","text":"计算无关模型","correct":false},{"key":"B","text":"计算相关模型","correct":true},{"key":"C","text":"平台无关模型","correct":false},{"key":"D","text":"平台相关模型","correct":false}]', 'B', '此题考察模型驱动的体系结构的相关概念，属于超纲题， 建议了解即可。模型驱动的体系结构（MDA）方法。该方法建议创建计算无关模型（CIM）、平台无关模型（PIM）和平台相关模型（PSM）三种类型的抽象系统模型，分别对系统的领域抽象、运转过程和平台实现进行建模。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3356, 'question-system-analyst-2022-05-comprehensive-13262', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-系统运行与维护', '遗留系统 （Legacy System）是指任何基本上不能进行修改和演化以满足新的业务需求变化的信息系统。针对遗留系统的再利用问题，通常从技术水平和业务价值两个维度进行考量，对于高水平、低价值的遗留系统，通常采用 （ 问题1 ） 策略；对于高水平、高价值的遗留系统，通常采用 （ 问题2 ） 策略。', '[{"key":"A","text":"淘汰","correct":false},{"key":"B","text":"继承","correct":false},{"key":"C","text":"改造","correct":true},{"key":"D","text":"集成","correct":false}]', 'C', '此题是考察遗留系统的演化策略相关概念，出自书本 15 章，建议必须掌握。其中淘汰是最好理解的（水平又低价值又低必定淘汰）。另外三个大家可能会搞混，群里也有人问过。这里我就详细说明加强大家的记忆。高水平低价值，意味着业务价值低，使用场景比较单一，这个时候就要把这些系统集成起来，以免形成孤岛。低水平高价值意味着代码很难维护（屎山）。但因为它承载着核心业务，一直跑的很好，所以你也不敢轻易动它的代码，只能做点修修补补的操作，这叫继承。那么高水平高价值呢，是既可以维护又承载核心业务的代码，企业可以根据需求大胆改动的，在此基础上增强新的功能，这就是改造。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3357, 'question-system-analyst-2022-05-comprehensive-13261', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-系统运行与维护', '遗留系统 （Legacy System）是指任何基本上不能进行修改和演化以满足新的业务需求变化的信息系统。针对遗留系统的再利用问题，通常从技术水平和业务价值两个维度进行考量，对于高水平、低价值的遗留系统，通常采用 （ 问题1 ） 策略；对于高水平、高价值的遗留系统，通常采用 （ 问题2 ） 策略。', '[{"key":"A","text":"淘汰","correct":false},{"key":"B","text":"继承","correct":false},{"key":"C","text":"改造","correct":false},{"key":"D","text":"集成","correct":true}]', 'D', '此题是考察遗留系统的演化策略相关概念，出自书本 15 章，建议必须掌握。其中淘汰是最好理解的（水平又低价值又低必定淘汰）。另外三个大家可能会搞混，群里也有人问过。这里我就详细说明加强大家的记忆。高水平低价值，意味着业务价值低，使用场景比较单一，这个时候就要把这些系统集成起来，以免形成孤岛。低水平高价值意味着代码很难维护（屎山）。但因为它承载着核心业务，一直跑的很好，所以你也不敢轻易动它的代码，只能做点修修补补的操作，这叫继承。那么高水平高价值呢，是既可以维护又承载核心业务的代码，企业可以根据需求大胆改动的，在此基础上增强新的功能，这就是改造。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3358, 'question-system-analyst-2022-05-comprehensive-13224', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-系统分析', '基于模型的系统工程作为一种 （ 问题1 ） ，为了应对基于文档的传统系统工程工作模式在复杂产品和系统研发时面临的挑战，以逻辑连贯一致的多视角系统模型为桥梁和框架，实现跨领域模型的可追踪、可验证和动态关联，驱动人工系统生存周期内各阶段和各层级内的系统工程过程和活动，使其可管理、可复现、可重用，进而打破专业壁垒，破解设计和工艺、研发和制造、研制和使用维护的分离，极大地提高沟通协同效率，实现以模型驱动的方法来采集、捕获和提炼数据、信息和知识。', '[{"key":"A","text":"形式化的建模方法学","correct":true},{"key":"B","text":"非形式化的建模方法学","correct":false},{"key":"C","text":"结构化建模方法学","correct":false},{"key":"D","text":"面向对象建模方法学","correct":false}]', 'A', '此题考察形式化建模相关知识，属于超纲题，建议了解即可。基于模型的系统工程作为一种形式化的建模方法学。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3359, 'question-system-analyst-2022-05-comprehensive-13218', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-新技术应用', '数据中台依据企业特有的业务模式和组织架构，通过有形的产品和实施方法论支撑，构建了一套持续不断将数据变成资产并服务于业务的机制。数据中台需要具备的4个核心能力为 （ 问题1 ） ，让企业员工、客户、伙伴能够方便地应用数据。', '[{"key":"A","text":"数据汇聚整合、数据清洗、数据加密、数据建模","correct":false},{"key":"B","text":"数据汇聚整合、数据清洗、数据加密、数据分发","correct":false},{"key":"C","text":"数据汇聚整合、数据提纯加工、数据服务可视化、数据价值变现","correct":true},{"key":"D","text":"数据清洗、数据加密、数据解密、数据建模","correct":false}]', 'C', '此题考察数据中台的相关概念，属于超纲题，但是建议掌握。数据中台是企业建设完整的数据资产体系的必要工具，具备数据汇聚整合、数据提纯加工、数据服务可视化、价值变现四个核心能力。它需要整合和完善数据资源，将业务数据转化为数据资产，并提供便捷、快速的数据服务能力，帮助企业快速实现数据资产的可视化分析并为企业数据化运营赋能，最终实现数据洞察变成直接驱动业务行动的核心动能，推进数据实践。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3360, 'question-system-analyst-2022-05-comprehensive-13273', '系统分析师', 'null', 2022, '2022年5月系统分析师综合知识-专业英语', 'Requirements validation is the process of checking that requirements actually define the system that the customer really wants. It overlaps with analysis as it is concerned with finding problems with the requirements. Requirements validation is important because errors in a requirements document can lead to extensive rework costs when these problems are discovered during development or after the system is in service. The cost of fixing a requirements problem by making a system change is usually much greater than repairing design or coding errors. The reason for this is that a change to the requirements usually means that the system design and implementation must also be changed. Furthermore, the system must then be re-tested.

During the requirements validation process, different types of checks should be carried out on the requirements in the requirements document. These checks include:

1. （ 问题1 ） : A user may think that a system is needed to perform certain function. However, further thought and analysis may identify additional or different functions that are required. Systems have diverse stakeholders with different needs and any set of requirements is inevitably a compromise across the stakeholder community.

2. （ 问题2 ） : Requirements in the document should not conflict. That is, there should not be contradictory constraints or different descriptions of the same system function.

3. （ 问题3 ） : The requirements document should include requirements that define all functions and the constraints intended by the system user.

4. Realism checks: Using knowledge of existing technology, the requirements should be checked to ensure that they can actually be implemented. These checks should also take account of the （ 问题4 ） for the system development.

5. Verifiability: To reduce the potential for dispute between customer and contractor, system requirements should always be written so that they are verifiable. This means that you should be able to write a set of tests that can demonstrate that the delivered system meets each specified （ 问题5 ） .', '[{"key":"A","text":"requirement","correct":true},{"key":"B","text":"model","correct":false},{"key":"C","text":"design","correct":false},{"key":"D","text":"implementation","correct":false}]', 'A', '需求验证是检查需求是否实际定义了客户真正想要的系统的过程。它与分析重叠，因为它关注的是发现需求中的问题。需求验证是很重要的，因为当这些问题在开发过程中或系统投入使用后被发现时，需求文件中的错误会导致大量的返工成本。通过改变系统来修复需求问题的成本通常比修复设计或编码错误要大得多。原因是对需求的改变通常意味着系统的设计和实施也必须改变。此外，还必须重新测试系统。

在需求验证过程中，应该对需求文件中的需求进行不同类型的检查。这些检查包括：

1. （ ）: 用户可能认为需要一个系统来执行某些功能。然而，进一步的思考和分析可能会发现需要额外的或不同的功能。系统有不同的利益相关者，有不同的需求，任何一套需求都不可避免地是整个利益相关者群体的妥协。

2. （ ） : 文件中的要求不应冲突。也就是说，不应该有相互矛盾的约束或对同一系统功能的不同描述。

3. （ ） : 需求文件应该包括定义所有功能的需求和系统用户所期望的约束。

4. 现实性检查。利用现有技术的知识，应该对需求进行检查，以确保它们能够真正被实现。这些检查也应该考虑到系统开发的 （ ） 。

5. 可验证性。为了减少客户和承包商之间潜在的争议，系统需求的编写应该始终是可验证的。这意味着你应该能够编写一套测试，以证明所交付的系统符合每一个指定的 （ ） 。

（1）A. 安全检查 B. 有效性检查 C. 一致性检查 D. 完整性检查

（2）A. 安全检查 B. 安全检查 C. 一致性检查 D. 可用性检查

（3）A. 一致性检查 B. 可用性检查 C. 操作性检查 D. 完整性检查

（4）A. 工具 B. 测试 C. 模型 D. 预算和时间表

（5）A. 需求 B. 模型 C. 设计 D. 实施', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
