INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3416, 'question-system-analyst-2021-05-comprehensive-13172', '系统分析师', '计算机基础', 2021, '2021年5月系统分析师综合知识-信号量', '进程P1、P2、P3、P4、P5和P6的前趋图如下所示：

若用PV操作控制这6个进程的同步与互斥的程序如下，那么程序中的空①和空②处应分别为 （ 问题1 ） ；空③和空④处应分别为 （ 问题2 ） ；空⑤和空⑥处应分别为 （ 问题3 ） 。', '[{"key":"A","text":"V（S1）和 P（S2）P（S3）","correct":false},{"key":"B","text":"P（S1）和 V（S2）V（S3）","correct":false},{"key":"C","text":"V（S1）和 V（S2）V（S3）","correct":true},{"key":"D","text":"P（S1）和 P（S2）P（S3）","correct":false}]', 'C', '此题是信号量与前趋图相结合的一道题目，出自书本 3.2.2 章节，考的频率非常之高，建议必须掌握。解这类题目可以先标注出信号量，如图所示：

前趋图的先后关系代表了后者必须等待前者执行完才能做一下步操作，此时前者结束时发出 V 操作释放资源，后者发出 P 操作请求资源进行等待。根据此判断原则可知答案。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3417, 'question-system-analyst-2021-05-comprehensive-13170', '系统分析师', '嵌入式系统', 2021, '2021年5月系统分析师综合知识-嵌入式系统', '嵌入式系统初始化过程通常包括三个环节：片级初始化、板级初始化和系统初始化。以下关于系统级初始化主要任务的描述，准确的是 （ 问题1 ） 。', '[{"key":"A","text":"完成嵌入式微处理器的初始化","correct":false},{"key":"B","text":"以软件初始化为主，主要进行操作系统的初始化","correct":true},{"key":"C","text":"完成嵌入式微处理器以外的其他硬件设备的初始化","correct":false},{"key":"D","text":"设置嵌入式微处理器的核心寄存器和控制寄存器工作状态","correct":false}]', 'B', '此题考查嵌入式系统相关的基础知识，属于扩展题目，建议了解即可。嵌入式系统初始化过程分为三个主要环节：片级初始化、板级初始化和系统级初始化。片级初始化包括设置嵌入式微处理器的核心寄存器和控制寄存器、工作模式等，是一个纯硬件的初始化过程。板级初始化除了完成其他硬件设备的初始化，还需要设置某些软件的数据结构和参数，建立硬件和软件环境。系统初始化是以软件初始化为主，在操作系统层面完成设备驱动程序的加载和初始化，建立系统内存区，加载并初始化其他系统软件模块。最后，操作系统创建应用程序环境并启动应用。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3418, 'question-system-analyst-2021-05-comprehensive-13139', '系统分析师', '嵌入式系统', 2021, '2021年5月系统分析师综合知识-嵌入式系统', '在多核与多处理技术融合的系统中，对调试问题提出许多新挑战。其主要原因是由于系统的复杂度在不断增加，需要通过优化硬件和软件来充分发挥系统的性能潜力。以下对调试难点问题的描述，不正确的是 （ 问题1 ） 。', '[{"key":"A","text":"在多核、多电路板和多操作系统环境中对操作系统和应用代码进行调试","correct":false},{"key":"B","text":"调试单一芯片中的同构和异构调试方法，进而实现整个系统的协同调试","correct":false},{"key":"C","text":"有效利用JTAG与基于代理调试方法，确保不同调试工具之间的顺畅协同","correct":false},{"key":"D","text":"在多核环境中调试应用程序不需考虑同步机制","correct":true}]', 'D', '本题考查多核处理的相关知识，虽然偏门，但是难度不大，建议掌握。多核处理器可以提高计算速度同时降低能耗，但多核调试技术仍然是一个挑战。主要问题包括共享资源管理、多操作系统调试、JTAG接口和带宽优化、同构和异构多核调试、多种调试工具的协同等。本题中，D 选项“在多核环境中调试应用程序不需考虑同步机制”是不对的，因为如果应用程序在调试中不能保证同步，就会带来结果的二义性。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3419, 'question-system-analyst-2021-05-comprehensive-13137', '系统分析师', '嵌入式系统', 2021, '2021年5月系统分析师综合知识-嵌入式系统', '在嵌入式系统中，板上通信接口是指用于将各种集成电路与其他外围设备交互连接的电路或总线。常用的板上通信接口包括 I2C、SPI、 UART 等。其中，I2C总 线通常被用于多主机场景。以下关于I2C总线不正确的说法是 （ 问题1 ） 。', '[{"key":"A","text":"I2C 总线是一种同步、双向、半双工的两线式串行接口总线","correct":false},{"key":"B","text":"I2C 总线由两条总线组成：串行时钟总线 SCL 和串行数据总线 SDA","correct":false},{"key":"C","text":"I2C 总线是一种同步、双向、全双工的 4 线式串行接口总线","correct":true},{"key":"D","text":"I2C 最初的设计目标是为微处理器/微控制器系统与电视机外围芯片之间的连接提供简单的方法","correct":false}]', 'C', '此题考察嵌入式系统通信接口的相关概念，建议了解即可。SPI 总线是同步、双向、全双工的 4 线式串行接口总线，而 I2C 总线则是同步、双向、半双工的两线式串行接口总线。SPI 是由单个主设备和多个从设备构成，而 I2C 总线是一个共享的总线系统，可以将多个设备连接到该系统上。“I2C 总线是一种同步、双向、全双工的4线式串行接口总线”的说法是错误的。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3420, 'question-system-analyst-2021-05-comprehensive-13159', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息资源管理', '信息资源与人力、物力、财力和自然资源一样，都是企业的重要资源，信息资源管理（Information Resource Management，IRM）可通过企业内外信息流的畅通和信息资源的有效利用，来提高企业的效益和竞争力。IRM包括强调对数据控制的 （ 问题1 ） ， 和关心企业管理人员如何获取和处理信息的信息处理管理。IRM的起点和基础是 （ 问题2 ） 。', '[{"key":"A","text":"建立信息架构","correct":false},{"key":"B","text":"建立信息资源目录","correct":true},{"key":"C","text":"业务与IT整合","correct":false},{"key":"D","text":"信息与业务整合","correct":false}]', 'B', '此题考查信息资源管理相关知识，出自书本 7.6 章节，建议了解即可。信息资源管理（IRM）通过信息资源的畅通和有效利用提高企业的效益和竞争力。IRM 包括数据资源管理和信息处理管理，前者强调数据的控制和安全，后者则关注企业管理人员如何获取和处理信息以及信息资源的重要性。在 IRM 中，建立信息资源目录是起点和基础，分类是 IRM 中最为复杂的工作之一，应当遵循简洁、独立、可操作的原则，一般从管理维度、信息来源维度、应用主题维度分类。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3421, 'question-system-analyst-2021-05-comprehensive-13158', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息资源管理', '信息资源与人力、物力、财力和自然资源一样，都是企业的重要资源，信息资源管理（Information Resource Management，IRM）可通过企业内外信息流的畅通和信息资源的有效利用，来提高企业的效益和竞争力。IRM包括强调对数据控制的 （ 问题1 ） ， 和关心企业管理人员如何获取和处理信息的信息处理管理。IRM的起点和基础是 （ 问题2 ） 。', '[{"key":"A","text":"数据来源管理","correct":false},{"key":"B","text":"信息架构管理","correct":false},{"key":"C","text":"信息来源管理","correct":false},{"key":"D","text":"数据资源管理","correct":true}]', 'D', '此题考查信息资源管理相关知识，出自书本 7.6 章节，建议了解即可。信息资源管理（IRM）通过信息资源的畅通和有效利用提高企业的效益和竞争力。IRM 包括数据资源管理和信息处理管理，前者强调数据的控制和安全，后者则关注企业管理人员如何获取和处理信息以及信息资源的重要性。在 IRM 中，建立信息资源目录是起点和基础，分类是 IRM 中最为复杂的工作之一，应当遵循简洁、独立、可操作的原则，一般从管理维度、信息来源维度、应用主题维度分类。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3422, 'question-system-analyst-2021-05-comprehensive-13147', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息系统战略规划方法', '信息系统战略规划方法中的战略一致性模型由 （ 问题1 ） 领域构成。', '[{"key":"A","text":"企业经营管理、组织与业务流程、信息系统战略","correct":false},{"key":"B","text":"企业经营战略、信息系统战略、组织与业务流程、IT 基础架构","correct":true},{"key":"C","text":"企业战略、业务流程、信息系统、IT 基础架构","correct":false},{"key":"D","text":"企业规划战略、组织与业务流程、信息系统战略","correct":false}]', 'B', '此题考察信息系统战略规划方法，出自书本 7.4 章节，建议了解即可。战略一致性模型也称作战略对应模型、战略策应模型，是由John Handerson 于1994年提出的一种信息系统规划方法，它可以帮助企业检查企业战略与信息基础架构之间的一致性，由企业经营战略、 组织与业务流程、信息系统战略、IT基础架构四大领域构成。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3423, 'question-system-analyst-2021-05-comprehensive-13143', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息系统战略规划方法', '企业信息化规划涉及多个领域的融合，它是企业战略、管理规划、业务流程重组等内容的综合规划活动。其中， （ 问题1 ） 规划是评价环境和企业现状， 进而选择和确定企业的总体和长远目标，制定和抉择实现目标的行动方案。 （ 问题2 ） 战略规划关注如何通过信息系统来支撑业务流程的运作，进而实现企业的关键业务目标。', '[{"key":"A","text":"业务流程","correct":false},{"key":"B","text":"业务目标","correct":false},{"key":"C","text":"信息系统","correct":true},{"key":"D","text":"信息技术","correct":false}]', 'C', '此题考察的知识点为企业信息化规划相关概念，出自书本 7.2 章节，建议了解即可。企业战略规划是指依据企业外部环境和自身条件的状况及其变化来制定和实施战略，并根据对实施过程与结果的评价和反馈来调整，制定新战略的过程。信息系统战略规划关注如何通过信息系统来支撑业务流程的运作，进而实现企业的关键业务目标。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3424, 'question-system-analyst-2021-05-comprehensive-13142', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息系统战略规划方法', '企业信息化规划涉及多个领域的融合，它是企业战略、管理规划、业务流程重组等内容的综合规划活动。其中， （ 问题1 ） 规划是评价环境和企业现状， 进而选择和确定企业的总体和长远目标，制定和抉择实现目标的行动方案。 （ 问题2 ） 战略规划关注如何通过信息系统来支撑业务流程的运作，进而实现企业的关键业务目标。', '[{"key":"A","text":"企业战略","correct":true},{"key":"B","text":"企业目标","correct":false},{"key":"C","text":"业务目标","correct":false},{"key":"D","text":"企业管理","correct":false}]', 'A', '此题考察的知识点为企业信息化规划相关概念，出自书本 7.2 章节，建议了解即可。企业战略规划是指依据企业外部环境和自身条件的状况及其变化来制定和实施战略，并根据对实施过程与结果的评价和反馈来调整，制定新战略的过程。信息系统战略规划关注如何通过信息系统来支撑业务流程的运作，进而实现企业的关键业务目标。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3425, 'question-system-analyst-2021-05-comprehensive-13154', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息系统开发方法', '结构化方法属于 （ 问题1 ） 的开发方法，强调开发方法的结构合理性，以及所开发系统的结构合理性。而 （ 问题2 ） 是一种根据用户初步需求，利用系统开发工具，快速地建立一个系统模型展示给用户，在此基础上与用户交流，最终实现用户需求的信息系统快速开发的方法。', '[{"key":"A","text":"面向智能体方法","correct":false},{"key":"B","text":"原型化方法","correct":true},{"key":"C","text":"面向对象方法","correct":false},{"key":"D","text":"面向服务方法","correct":false}]', 'B', '此题考查信息系统开发方法的相关概念，出自书本 7.3 章节，建议掌握。信息系统开发方法包括结构化方法、原型法和面向对象方法，以及面向服务的方法。结构化方法的主要特点是自顶向下、逐步求精和模块化设计，其开发过程划分为系统规划、系统分析、系统设计、系统实施、系统维护等阶段；原型法是根据用户需求快速建立系统模型展示给用户，反复修改和补充；面向对象方法认为客观世界是由各种对象组成的，采用面向对象的信息建模概念来构造系统；面向服务的开发方法则是将相关对象按业务功能进行分组，采用接口的形式暴露出来实现跨构件的功能调用。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3426, 'question-system-analyst-2021-05-comprehensive-13153', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息系统开发方法', '结构化方法属于 （ 问题1 ） 的开发方法，强调开发方法的结构合理性，以及所开发系统的结构合理性。而 （ 问题2 ） 是一种根据用户初步需求，利用系统开发工具，快速地建立一个系统模型展示给用户，在此基础上与用户交流，最终实现用户需求的信息系统快速开发的方法。', '[{"key":"A","text":"自底向上","correct":false},{"key":"B","text":"层次性","correct":false},{"key":"C","text":"自顶向下","correct":true},{"key":"D","text":"对象化","correct":false}]', 'C', '此题考查信息系统开发方法的相关概念，出自书本 7.3 章节，建议掌握。信息系统开发方法包括结构化方法、原型法和面向对象方法，以及面向服务的方法。结构化方法的主要特点是自顶向下、逐步求精和模块化设计，其开发过程划分为系统规划、系统分析、系统设计、系统实施、系统维护等阶段；原型法是根据用户需求快速建立系统模型展示给用户，反复修改和补充；面向对象方法认为客观世界是由各种对象组成的，采用面向对象的信息建模概念来构造系统；面向服务的开发方法则是将相关对象按业务功能进行分组，采用接口的形式暴露出来实现跨构件的功能调用。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3427, 'question-system-analyst-2021-05-comprehensive-13152', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息系统开发方法', '在信息系统开发方法中， （ 问题1 ） 假定待开发的系统是一个结构化的系统，其基本思想是将系统的生命周期划分为 （ 问题2 ） 、系统分析、系统设计、系统实施、系统维护等阶段。这种方法遵循系统工程原理，按照事先设计好的程序和步骤，使用一定的开发工具，完成规定的文档，以结构化和 （ 问题3 ） 的方式进行信息系统的开发工作。', '[{"key":"A","text":"对象化","correct":false},{"key":"B","text":"服务化","correct":false},{"key":"C","text":"模块化","correct":true},{"key":"D","text":"组件化","correct":false}]', 'C', '此题考查结构化方法的相关概念，出自书本 7.3 章节，建议必须掌握。信息系统开发方法，其主要包括结构化分析、结构化设计和结构化程序设计三部分，遵循自顶向下、逐步求精和模块化设计的理念。结构化方法的主要特点包括开发目标清晰化、工作阶段程式化、开发文档规范化和设计方法结构化。结构化方法被广泛应用于各个行业的信息系统开发中，特别适合于那些业务工作比较成熟、定型的系统。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3428, 'question-system-analyst-2021-05-comprehensive-13151', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息系统开发方法', '在信息系统开发方法中， （ 问题1 ） 假定待开发的系统是一个结构化的系统，其基本思想是将系统的生命周期划分为 （ 问题2 ） 、系统分析、系统设计、系统实施、系统维护等阶段。这种方法遵循系统工程原理，按照事先设计好的程序和步骤，使用一定的开发工具，完成规定的文档，以结构化和 （ 问题3 ） 的方式进行信息系统的开发工作。', '[{"key":"A","text":"系统规划","correct":true},{"key":"B","text":"系统定义","correct":false},{"key":"C","text":"需求定义","correct":false},{"key":"D","text":"实现定义","correct":false}]', 'A', '此题考查结构化方法的相关概念，出自书本 7.3 章节，建议必须掌握。信息系统开发方法，其主要包括结构化分析、结构化设计和结构化程序设计三部分，遵循自顶向下、逐步求精和模块化设计的理念。结构化方法的主要特点包括开发目标清晰化、工作阶段程式化、开发文档规范化和设计方法结构化。结构化方法被广泛应用于各个行业的信息系统开发中，特别适合于那些业务工作比较成熟、定型的系统。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3429, 'question-system-analyst-2021-05-comprehensive-13150', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息系统开发方法', '在信息系统开发方法中， （ 问题1 ） 假定待开发的系统是一个结构化的系统，其基本思想是将系统的生命周期划分为 （ 问题2 ） 、系统分析、系统设计、系统实施、系统维护等阶段。这种方法遵循系统工程原理，按照事先设计好的程序和步骤，使用一定的开发工具，完成规定的文档，以结构化和 （ 问题3 ） 的方式进行信息系统的开发工作。', '[{"key":"A","text":"结构化方法","correct":true},{"key":"B","text":"面向对象方法","correct":false},{"key":"C","text":"原型法","correct":false},{"key":"D","text":"面向服务方法","correct":false}]', 'A', '此题考查结构化方法的相关概念，出自书本 7.3 章节，建议必须掌握。信息系统开发方法，其主要包括结构化分析、结构化设计和结构化程序设计三部分，遵循自顶向下、逐步求精和模块化设计的理念。结构化方法的主要特点包括开发目标清晰化、工作阶段程式化、开发文档规范化和设计方法结构化。结构化方法被广泛应用于各个行业的信息系统开发中，特别适合于那些业务工作比较成熟、定型的系统。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3430, 'question-system-analyst-2021-05-comprehensive-13146', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-信息系统开发方法', '以下关于信息系统开发方法的描述，正确的是 （ 问题1 ） 。', '[{"key":"A","text":"生命周期法是一种传统的信息系统开 发方法，由结构化分析（SA）、结构化设计（SD）和结构化程序设计（SP）三部分组成。它是目前应用最成熟的开发方法，特别适合于数据处理领域的问题，适应于规模较大、比较复杂的系统开发","correct":false},{"key":"B","text":"面向对象（OO）方法认为任何事物都是对象，每一个对象都有自己的运动规律和内部状态，都属于某个对象“类”，是该对象类的一个元素。结构化方法是自顶向下的，而OO方法则是自底向上，在信息系统开发中两者不可共存","correct":false},{"key":"C","text":"面向服务（SO）的系统不能使用面向对象设计（OOD）来构建单个服务","correct":false},{"key":"D","text":"原型法适用于技术层面难度不大、分析层面难度大的系统开发","correct":true}]', 'D', '此题考查对信息系统开发方法的相关概念，出自书本 7.3 章节，建议必须掌握。结构化开发方法是一种传统的信息系统开发方法，生命周期可分为规划、分析、设计、实施、维护等阶段，其精髓是自顶向下、逐步求精和模块化设计。面向对象方法认为任何事物都是对象，面向对象开发方法是以用例驱动的、以体系结构为中心的、迭代的和渐增式的开发过程。对于大型信息系统开发，通常是将结构化方法和面向对象方法结合起来。原型化方法是根据用户初步需求，快速建立一个系统模型展示给用户，在此基础上与用户交流，最终实现用户需求的信息系统快速开发方法。对于需求不明确的系统开发，原型化方法相对于结构化方法和面向对象方法而言对用户更友好，但对于技术层面的困难远大于其分析层面的系统，则不宜用原型法。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3431, 'question-system-analyst-2021-05-comprehensive-13157', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-企业资源规划和实施', 'ERP 是一种融合了企业最佳实践和先进信息技术的新型管理工具，它扩充了 （ 问题1 ） 和制造资源计划的管理范围，将 （ 问题2 ） 和企业内部的采购、生产、销售以及客户紧密联系起来，可对供应链上的所有环节进行有效管理，实现对企业的动态控制和各种资源的集成和优化，提升基础管理水平，追求企业资源的合理高效利用。ERP 的作用是在协调与整合企业各方面资源运营的过程中，全面实现 （ 问题3 ） 和企业对市场变化的快速反应，降低市场波动给企业带来的经营风险，帮助企业以更少的资源投入获得更多的投资回报。', '[{"key":"A","text":"信息隐蔽","correct":false},{"key":"B","text":"信息重构","correct":false},{"key":"C","text":"信息共享","correct":true},{"key":"D","text":"信息更新","correct":false}]', 'C', '此题考查企业资源规划的相关概念，出自书本 7.5，建议了解即可。ERP 作为一种新型的管理工具，融合了企业最佳实践和先进信息技术，扩充了管理信息系统和制造资源计划的管理范围，将供应商和企业内部的采购、生产、销售以及客户紧密联系起来，实现对企业的动态控制和各种资源的集成和优化。可以从管理思想、软件产品和管理系统三个角度来理解ERP的概念。ERP的作用主要包括全面实现信息共享降低市场波动给企业带来的经营风险、帮助企业以更少的资源投入获得更多的投资回报等，具体表现在供应制造、分销渠道、集中财务管理、客户关系管理、人力资源管理、项目管理、资产维护等方面。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3432, 'question-system-analyst-2021-05-comprehensive-13156', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-企业资源规划和实施', 'ERP 是一种融合了企业最佳实践和先进信息技术的新型管理工具，它扩充了 （ 问题1 ） 和制造资源计划的管理范围，将 （ 问题2 ） 和企业内部的采购、生产、销售以及客户紧密联系起来，可对供应链上的所有环节进行有效管理，实现对企业的动态控制和各种资源的集成和优化，提升基础管理水平，追求企业资源的合理高效利用。ERP 的作用是在协调与整合企业各方面资源运营的过程中，全面实现 （ 问题3 ） 和企业对市场变化的快速反应，降低市场波动给企业带来的经营风险，帮助企业以更少的资源投入获得更多的投资回报。', '[{"key":"A","text":"供应商","correct":true},{"key":"B","text":"开发商","correct":false},{"key":"C","text":"销售渠道","correct":false},{"key":"D","text":"建设商","correct":false}]', 'A', '此题考查企业资源规划的相关概念，出自书本 7.5，建议了解即可。ERP 作为一种新型的管理工具，融合了企业最佳实践和先进信息技术，扩充了管理信息系统和制造资源计划的管理范围，将供应商和企业内部的采购、生产、销售以及客户紧密联系起来，实现对企业的动态控制和各种资源的集成和优化。可以从管理思想、软件产品和管理系统三个角度来理解ERP的概念。ERP的作用主要包括全面实现信息共享降低市场波动给企业带来的经营风险、帮助企业以更少的资源投入获得更多的投资回报等，具体表现在供应制造、分销渠道、集中财务管理、客户关系管理、人力资源管理、项目管理、资产维护等方面。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3433, 'question-system-analyst-2021-05-comprehensive-13155', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-企业资源规划和实施', 'ERP 是一种融合了企业最佳实践和先进信息技术的新型管理工具，它扩充了 （ 问题1 ） 和制造资源计划的管理范围，将 （ 问题2 ） 和企业内部的采购、生产、销售以及客户紧密联系起来，可对供应链上的所有环节进行有效管理，实现对企业的动态控制和各种资源的集成和优化，提升基础管理水平，追求企业资源的合理高效利用。ERP 的作用是在协调与整合企业各方面资源运营的过程中，全面实现 （ 问题3 ） 和企业对市场变化的快速反应，降低市场波动给企业带来的经营风险，帮助企业以更少的资源投入获得更多的投资回报。', '[{"key":"A","text":"管理信息系统","correct":true},{"key":"B","text":"人力资源系统","correct":false},{"key":"C","text":"企业发展计划","correct":false},{"key":"D","text":"企业财务系统","correct":false}]', 'A', '此题考查企业资源规划的相关概念，出自书本 7.5，建议了解即可。ERP 作为一种新型的管理工具，融合了企业最佳实践和先进信息技术，扩充了管理信息系统和制造资源计划的管理范围，将供应商和企业内部的采购、生产、销售以及客户紧密联系起来，实现对企业的动态控制和各种资源的集成和优化。可以从管理思想、软件产品和管理系统三个角度来理解ERP的概念。ERP的作用主要包括全面实现信息共享降低市场波动给企业带来的经营风险、帮助企业以更少的资源投入获得更多的投资回报等，具体表现在供应制造、分销渠道、集中财务管理、客户关系管理、人力资源管理、项目管理、资产维护等方面。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3434, 'question-system-analyst-2021-05-comprehensive-13160', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-企业信息系统', '电子商务是指买卖双方利用现代开放的 Internet 网络，按照一定的标准所进行的各类商业活动。电子商务可具有不同的模式，其中个人工作者给消费者提供服务属于 （ 问题1 ） 。', '[{"key":"A","text":"B2B","correct":false},{"key":"B","text":"C2C","correct":true},{"key":"C","text":"B2C","correct":false},{"key":"D","text":"C2B","correct":false}]', 'B', '此题考察电子商务相关的基础知识，建议掌握。个人工作者向消费者提供服务，通过互联网直接交易，符合 C2C 模式。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3435, 'question-system-analyst-2021-05-comprehensive-13149', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-企业信息系统', '业务流程重组（BPR）遵循的原则不包括 （ 问题1 ） 。', '[{"key":"A","text":"以流程为中心的原则","correct":false},{"key":"B","text":"利润最大化的原则","correct":true},{"key":"C","text":"以客户为导向的原则","correct":false},{"key":"D","text":"以人为本的原则","correct":false}]', 'B', '此题考查业务流程重组的相关概念，出自书本 7.9 章节，建议了解即可。业务流程重组 BPR 旨在通过重组和优化企业战略、运营流程、系统、政策、组织和结构，实现工作流程和生产力的最优化，从而降低成本、提高顾客满意度和员工自我价值实现的追求，达到效率和效益改善的目的。BPR 强调流程实现，注重长期发展能力，倡导以流程为中心、以人为本、以客户为导向的原则。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3436, 'question-system-analyst-2021-05-comprehensive-13148', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-企业信息系统', '以下关于企业信息系统的描述，错误的是 （ 问题1 ） 。', '[{"key":"A","text":"客户关系管理（CRM）的支柱性功能是市场营销和客户服务，其根本要求是与客户建立一种互相学习的关系，并在此基础上提供完善的个性化服务","correct":false},{"key":"B","text":"供应链管理（SCM）整合并优化了供应商、制造商、零售商的业务效率，使商品以正确的数量、正确的品质、在正确的地点、以正确的时间、最佳的成本进行生产和销售。SCM包括计划、采购、制造、配送、退货五大基本内容","correct":false},{"key":"C","text":"产品数据管理（PDM）的核心功能包括数据库和文档管理、产品结构与配置管理、生命周期管理和流程管理、集成开发接口，第二代PDM产品建立在Internet平台、CORBA和Java技术基础之上","correct":true},{"key":"D","text":"可以说产品生命周期管理（PLM）包含了PDM的全部内容，PDM功能是PLM中的一个子集","correct":false}]', 'C', '此题考查对企业信息系统的组成及功能的理解，出自书本 7.7.3 章节，考察角度非常刁钻，建议了解即可。产品数据管理 PDM 是以产品为中心，通过计算机网络和数据库技术，把企业生产过程中所有与产品相关的信息和过程集成起来进行管理的技术，包括所有与产品相关信息和所有与产品相关过程的技术。通过实施 PDM，可以提高生产效率，有利于对产品的全生命周期进行管理，加强对于文档、图纸、数据的高效利用，使工作流程规范化。第三代PDM产品建立在Internet平台、CORBA和Java技术基础之上，支持以“标准企业职能”和“动态企业”思想为中心的企业信息分析方法，可以进行企业信息建模的分析和设计，实现包括文档管理、生命周期管理、工作流管理、产品结构管理、视图管理、变更管理、客户化应用等功能。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3437, 'question-system-analyst-2021-05-comprehensive-13145', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-企业信息系统', '决策支持系统（DSS）是辅助决策者通过数据、模型和知识，以人机交互方式进行半结构化或非结构化决策的计算机应用系统。其中， （ 问题1 ） 可以建立适当的算法产生决策方案，使决策方案得到较优解。DSS基本结构主要由四个部分组成，即数据库子系统、模型库子系统、推理部分和用户接口子系统。DSS用户是依靠 （ 问题2 ） 进行决策的。', '[{"key":"A","text":"数据库中的数据","correct":false},{"key":"B","text":"模型库中的模型","correct":true},{"key":"C","text":"知识库中的方法","correct":false},{"key":"D","text":"人机交互界面","correct":false}]', 'B', '本题考查决策支持系统的基本概念，但是考的比较细，属于难题。非结构化决策是指决策过程非常复杂，无法用确定的模型和语言来描述，也没有固定的决策规则和通用模型可以遵循，决策者的主观行为对决策效果有相当影响。半结构化决策是指决策过程和方法有一定的规律可以遵循，可以建立适当的算法产生决策方案，但难以确定最优方案。所以第一小问选择C。

DSS 是决策支持系统的缩写，主要由数据库子系统、模型库子系统、推理部分和用户接口子系统组成。数据库子系统存储、管理、提供与维护用于决策支持的数据，是支撑模型库子系统和方法库子系统的基础。数据库子系统由数据库、数据析取模块、数据字典、数据库管理系统和数据查询模块等部分组成。

模型库子系统是构建和管理模型的子系统，它是 DSS中最复杂和最难实现的部分。DSS用户是依靠模型库中的模型进行决策的，因此，DSS 是由模型驱动的（直接记住结论）。应用模型获得的输出结果可以分别起到以下三种作用：直接用于制定决策；对决策的制定提出建议；用来估计决策实施后可能产生的后果。模型库子系统主要由模型库和模型库管理系统两大部分组成。

推理部分由知识库（方法库）、知识库管理系统和推理机组成。知识库内存储的方法程序一般有排序算法、分类算法、最小生成树算法、最短路径算法、计划评审技术、线性规划、整数规划、动态规划、各种统计算法和组合算法等。

用户接口子系统是 DSS的人机交互界面，用以接收和检验用户请求，调用系统内部功能为决策服务，使模型运行、数据调用和知识推理达到有机的统一，有效地解决决策问题。

综上所述，第二问选项选项B。

拓展一下，这里模型和推理的区别在哪里。实际上模型是预定义的数学或算法工具，通过结构化数据计算输出量化结果（如最优解、预测值），用于直接决策或定量分析；而推理基于方法库中的规则 / 逻辑，通过动态匹配推导结论，处理非结构化知识（如专家经验），输出建议或解释，侧重定性分析。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3438, 'question-system-analyst-2021-05-comprehensive-13144', '系统分析师', '企业信息化战略与实施', 2021, '2021年5月系统分析师综合知识-企业信息系统', '决策支持系统（DSS）是辅助决策者通过数据、模型和知识，以人机交互方式进行半结构化或非结构化决策的计算机应用系统。其中， （ 问题1 ） 可以建立适当的算法产生决策方案，使决策方案得到较优解。DSS基本结构主要由四个部分组成，即数据库子系统、模型库子系统、推理部分和用户接口子系统。DSS用户是依靠 （ 问题2 ） 进行决策的。', '[{"key":"A","text":"结构化和半结构化决策","correct":false},{"key":"B","text":"半结构化决策","correct":true},{"key":"C","text":"非结构化决策","correct":false},{"key":"D","text":"半结构化和非结构化决策","correct":false}]', 'B', '本题考查决策支持系统的基本概念，但是考的比较细，属于难题。非结构化决策是指决策过程非常复杂，无法用确定的模型和语言来描述，也没有固定的决策规则和通用模型可以遵循，决策者的主观行为对决策效果有相当影响。半结构化决策是指决策过程和方法有一定的规律可以遵循，可以建立适当的算法产生决策方案，但难以确定最优方案。所以第一小问选择C。

DSS 是决策支持系统的缩写，主要由数据库子系统、模型库子系统、推理部分和用户接口子系统组成。数据库子系统存储、管理、提供与维护用于决策支持的数据，是支撑模型库子系统和方法库子系统的基础。数据库子系统由数据库、数据析取模块、数据字典、数据库管理系统和数据查询模块等部分组成。

模型库子系统是构建和管理模型的子系统，它是 DSS中最复杂和最难实现的部分。DSS用户是依靠模型库中的模型进行决策的，因此，DSS 是由模型驱动的（直接记住结论）。应用模型获得的输出结果可以分别起到以下三种作用：直接用于制定决策；对决策的制定提出建议；用来估计决策实施后可能产生的后果。模型库子系统主要由模型库和模型库管理系统两大部分组成。

推理部分由知识库（方法库）、知识库管理系统和推理机组成。知识库内存储的方法程序一般有排序算法、分类算法、最小生成树算法、最短路径算法、计划评审技术、线性规划、整数规划、动态规划、各种统计算法和组合算法等。

用户接口子系统是 DSS的人机交互界面，用以接收和检验用户请求，调用系统内部功能为决策服务，使模型运行、数据调用和知识推理达到有机的统一，有效地解决决策问题。

综上所述，第二问选项选项B。

拓展一下，这里模型和推理的区别在哪里。实际上模型是预定义的数学或算法工具，通过结构化数据计算输出量化结果（如最优解、预测值），用于直接决策或定量分析；而推理基于方法库中的规则 / 逻辑，通过动态匹配推导结论，处理非结构化知识（如专家经验），输出建议或解释，侧重定性分析。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3439, 'question-system-analyst-2021-05-comprehensive-13176', '系统分析师', 'null', 2021, '2021年5月系统分析师综合知识-项目管理', '某项目包括8个作业A~H，每天需要间接费用5万元，完成各作业所需的时间与直接费用、赶进度时每天需要增加的费用以及作业之间的衔接关系见下表。根据这些数据，以最低成本完成该项目需要 （ 问题1 ） 天。', '[{"key":"A","text":"13","correct":false},{"key":"B","text":"14","correct":true},{"key":"C","text":"15","correct":false},{"key":"D","text":"16","correct":false}]', 'B', '此题考察项目管理中时间管理相关概念，难度很大，建议学有余力再学。先将题目中的各个结点依赖关系画出来，如图所示：

关键路径为 B-G-H，所以，正常情况下该项目的工期为 8+4+3=15 天，所需经费=总直接费用+天数×每天的间接费用=150+15×5=225万元。

为了将项目压缩工期 1 天，则必须将关键路径上的某个作业压缩 1 天。关键路径上的三个作业 B、G、H 压缩每天需要增加的费用分别为 6、3、6 万元，显然应将 G 压缩 1 天，需要增加费用 3 万元，但会节省间接费用 5 万元，所以总成本将降为 223 万元，工期将是14天。此时的网络计划图如下。

此时，关键路径有两条 B-G-H 和 B-C。如果项目要再压缩 1 天，则需要在每条关键路径上都压缩 1 天，而且赶进度总增加的费用应低于 5 万元才能节省总成本。如果 B 压缩 1 天，则总成本将增加6-5=1万元；如果 C 和 G 都压缩 1 天，则总成本将增加 3+3-5=1 万元；如果 C 和 H 都压缩1天，则总成本将增加 3+6-5=4 万元。因此，只能压缩 G 1 天，以最低成本（223 万元）完成该项目需要14天。答案选择B选项。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3440, 'question-system-analyst-2021-05-comprehensive-13141', '系统分析师', 'null', 2021, '2021年5月系统分析师综合知识-项目管理', '在信息物理系统（CPS）设计时，风险分析工作贯穿在整个系统生命周期的各个阶段。通常，风险分为基本风险和特定风险。特定风险是指与人为因素或物理环境因素突变有关的事件，可能使系统进入不安全状态，进而导致系统故障。以下关于风险因素描述中，不属于特定风险的是 （ 问题1 ） 。', '[{"key":"A","text":"CPS 是集人机交互、物理过程和计算过程于一体的安全关键嵌入式系统，彼此之间相互融合，不可分割。由于CPS要处于不同的恶劣环境，因此，在计算系统设计时，由于环境变化所引发芯片失效的风险应作为特定风险加以考虑。","correct":true},{"key":"B","text":"人为因素需要考虑触发及参与CPS运行的执行者，以及执行者为完成具体任务针对CPS所做的一系列动作。","correct":false},{"key":"C","text":"物理因素的行为是一个随着时间变化的连续过程。外界的物理变化通过传 感器被监测、感知，进一步将监测的信号发送给计算系统。当外界物理参数随着时间变化到某一数值会影响传感器的正常运行，从而导致系统发生状态的变迁。","correct":false},{"key":"D","text":"环境中的冰雹、冰、雪、雷击、单粒子事件效应、温度和振动等因素都属于特定风险，其自然现象因素都有可能引起CPS系统的失效。","correct":false}]', 'A', '此题考查软件开发中的风险分析的基础知识，出自书本 20.8.2 章节，建议了解即可。风险是指某一事件发生存在着两种或两种以上的可能性，包括非个人行为引起的基本风险和个人行为引起的特定风险。基本风险对整个团体乃至整个社会产生影响，个人无法预防；而特定风险只与特定的个人或部门相关，易于控制和防范。解题的时候不要被题干的突变误导，要关注风险是否易于控制和防范。选项 A 的描述， CPS 会处于不同恶劣环境，这种失效是个人难于预防的，因此属于基本风险。选项 B 是指人的行为、动作所引起的 CPS 失效，显然是特定风险。选项 C 的说法中，关键描述"当外界物理参数随着时间变化到某一数值会影响传感器的正常运行，从而导致系统发生状态的变迁"是局部风险，也是可控制和预防的，因此也是一种特定风险。也是特定风险。选项 D 的说法是正确的，自然灾害所引起的风险是可控制、可防范的，那么自然现象引友的 CPS 系统的失效也是可预防的，它是特定风险。此题答案为 A。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3441, 'question-system-analyst-2021-05-comprehensive-13183', '系统分析师', 'null', 2021, '2021年5月系统分析师综合知识-系统可靠性分析与设计', '系统可靠性是系统在规定时间内及规定的环境条件下，完成规定功能的能力。系统可靠性包含四个子特征，其中 （ 问题1 ） 是指系统避免因错误的发生而导致失效的能力； （ 问题2 ） 是指系统依附于与可靠性相关的标准、约定或规定的能力。', '[{"key":"A","text":"成熟性","correct":false},{"key":"B","text":"容错性","correct":false},{"key":"C","text":"易恢复性","correct":false},{"key":"D","text":"可靠性的依从性","correct":true}]', 'D', '此题系统可靠性的相关概念，建议了解即可。系统可靠性的定义和包含的四个子特性，即成熟性、容错性、易恢复性和可靠性的依从性。成熟性是指系统避免因错误的发生而导致失效的能力。容错性是指系统在出现故障或违反指定接口的情况下，仍能够维持规定的性能级别的能力。易恢复性是指系统能够在发生失效的情况下，重建规定的性能级别并恢复受直接影响的数据的能力；可靠性的依从性是指系统符合与可靠性相关的标准、约定或规定的能力。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3442, 'question-system-analyst-2021-05-comprehensive-13182', '系统分析师', 'null', 2021, '2021年5月系统分析师综合知识-系统可靠性分析与设计', '系统可靠性是系统在规定时间内及规定的环境条件下，完成规定功能的能力。系统可靠性包含四个子特征，其中 （ 问题1 ） 是指系统避免因错误的发生而导致失效的能力； （ 问题2 ） 是指系统依附于与可靠性相关的标准、约定或规定的能力。', '[{"key":"A","text":"成熟性","correct":true},{"key":"B","text":"容错性","correct":false},{"key":"C","text":"易恢复性","correct":false},{"key":"D","text":"可靠性的依从性","correct":false}]', 'A', '此题系统可靠性的相关概念，建议了解即可。系统可靠性的定义和包含的四个子特性，即成熟性、容错性、易恢复性和可靠性的依从性。成熟性是指系统避免因错误的发生而导致失效的能力。容错性是指系统在出现故障或违反指定接口的情况下，仍能够维持规定的性能级别的能力。易恢复性是指系统能够在发生失效的情况下，重建规定的性能级别并恢复受直接影响的数据的能力；可靠性的依从性是指系统符合与可靠性相关的标准、约定或规定的能力。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3443, 'question-system-analyst-2021-05-comprehensive-13131', '系统分析师', 'null', 2021, '2021年5月系统分析师综合知识-多媒体基础', '使用 （ 问题1 ） 格式的文件存储视频动画数据可以提高网页内容的载入速度。', '[{"key":"A","text":"jpg","correct":false},{"key":"B","text":"avi","correct":false},{"key":"C","text":"gif","correct":true},{"key":"D","text":"rm","correct":false}]', 'C', '本题考查多媒体基础知识，属于超纲题，建议了解即可。网页载入速度会极大地影响用户的上网浏览体验，因此，在不损害浏览内容的前提下，尽量缩小文件的体积有利于提高网页内容的载入速度。在网页上展示动画时，一般会采用 gif 格式的文件来进行展示，该格式的文件属于动图，对缩小文件体积较为有利，并且能够完整地展示文件内容。', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3444, 'question-system-analyst-2021-05-comprehensive-13198', '系统分析师', 'null', 2021, '2021年5月系统分析师综合知识-专业英语', 'The objective of the systems analysis phase is to understand the proposed project, ensure that it will support business requirements, and build a solid foundation for system development. The systems analysis phase includes four main activities. （ 问题1 ） involves fact-finding to describe the current system and identification of the requirements for the new system, such as outputs, inputs, processes, performance, and security. （ 问题2 ） refer to the logical rules that are applied to transform the data into meaningful information. （ 问题3 ） continues the modeling process by learning how to represent graphically system data and processes using traditional structured analysis techniques. （ 问题4 ） combines data and the processes that act on the data into objects. These objects represent actual people, things, transactions, and events that affect the system. In （ 问题5 ） ， we will consider various development options and prepare for the transition to the systems design phase of the SDLC.', '[{"key":"A","text":"feasibility analysis","correct":false},{"key":"B","text":"development strategies","correct":true},{"key":"C","text":"architecture design","correct":false},{"key":"D","text":"technique outline","correct":false}]', 'B', '系统分析阶段的目标是了解提议的项目，确保它将支持业务需求，并为系统开发奠定坚实的基础。系统分析阶段包括四项主要活动。（）涉及事实调查，以描述当前系统，并识别新系统的需求，如输出、输入、过程、性能和安全。（）是指用于将数据转换为有意义的信息的逻辑规则。（）通过学习如何使用传统的结构化分析技术以图形方式表示系统数据和过程来继续建模过程。（）将数据和作用于数据的过程组合成对象。这些对象表示影响系统的实际人员、事物、事务和事件。在（）中，我们将考虑各种开发选项，并为过渡到系统开发生命周期的系统设计阶段做准备。

A.系统逻辑建模 B.用例建模 C.需求建模 D.应用程序建模

A.输出 B.输入 C.过程 D.模型

A.业务建模 B.数据库建模 C.结构化建模 D.数据和过程建模

A.对象建模 B.领域分析 C.组件建模 D.行为建模

A.可行性分析 B.开发策略 C.架构设计 D.技术概述', 1, 3, 'import', '2026-03-28 12:06:34', '2026-05-08 23:54:08', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3445, 'question-system-analyst-2021-05-comprehensive-13197', '系统分析师', 'null', 2021, '2021年5月系统分析师综合知识-专业英语', 'The objective of the systems analysis phase is to understand the proposed project, ensure that it will support business requirements, and build a solid foundation for system development. The systems analysis phase includes four main activities. （ 问题1 ） involves fact-finding to describe the current system and identification of the requirements for the new system, such as outputs, inputs, processes, performance, and security. （ 问题2 ） refer to the logical rules that are applied to transform the data into meaningful information. （ 问题3 ） continues the modeling process by learning how to represent graphically system data and processes using traditional structured analysis techniques. （ 问题4 ） combines data and the processes that act on the data into objects. These objects represent actual people, things, transactions, and events that affect the system. In （ 问题5 ） ， we will consider various development options and prepare for the transition to the systems design phase of the SDLC.', '[{"key":"A","text":"Object modeling","correct":true},{"key":"B","text":"Domain analysis","correct":false},{"key":"C","text":"Component modeling","correct":false},{"key":"D","text":"Behavior modeling","correct":false}]', 'A', '系统分析阶段的目标是了解提议的项目，确保它将支持业务需求，并为系统开发奠定坚实的基础。系统分析阶段包括四项主要活动。（）涉及事实调查，以描述当前系统，并识别新系统的需求，如输出、输入、过程、性能和安全。（）是指用于将数据转换为有意义的信息的逻辑规则。（）通过学习如何使用传统的结构化分析技术以图形方式表示系统数据和过程来继续建模过程。（）将数据和作用于数据的过程组合成对象。这些对象表示影响系统的实际人员、事物、事务和事件。在（）中，我们将考虑各种开发选项，并为过渡到系统开发生命周期的系统设计阶段做准备。

A.系统逻辑建模 B.用例建模 C.需求建模 D.应用程序建模

A.输出 B.输入 C.过程 D.模型

A.业务建模 B.数据库建模 C.结构化建模 D.数据和过程建模

