INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3446, 'question-system-analyst-2021-05-comprehensive-13196', '系统分析师', 'null', 2021, '2021年5月系统分析师综合知识-专业英语', 'The objective of the systems analysis phase is to understand the proposed project, ensure that it will support business requirements, and build a solid foundation for system development. The systems analysis phase includes four main activities. （ 问题1 ） involves fact-finding to describe the current system and identification of the requirements for the new system, such as outputs, inputs, processes, performance, and security. （ 问题2 ） refer to the logical rules that are applied to transform the data into meaningful information. （ 问题3 ） continues the modeling process by learning how to represent graphically system data and processes using traditional structured analysis techniques. （ 问题4 ） combines data and the processes that act on the data into objects. These objects represent actual people, things, transactions, and events that affect the system. In （ 问题5 ） ， we will consider various development options and prepare for the transition to the systems design phase of the SDLC.', '[{"key":"A","text":"Business modeling","correct":false},{"key":"B","text":"Database modeling","correct":false},{"key":"C","text":"Structure modeling","correct":false},{"key":"D","text":"Data and process modeling","correct":true}]', 'D', '系统分析阶段的目标是了解提议的项目，确保它将支持业务需求，并为系统开发奠定坚实的基础。系统分析阶段包括四项主要活动。（）涉及事实调查，以描述当前系统，并识别新系统的需求，如输出、输入、过程、性能和安全。（）是指用于将数据转换为有意义的信息的逻辑规则。（）通过学习如何使用传统的结构化分析技术以图形方式表示系统数据和过程来继续建模过程。（）将数据和作用于数据的过程组合成对象。这些对象表示影响系统的实际人员、事物、事务和事件。在（）中，我们将考虑各种开发选项，并为过渡到系统开发生命周期的系统设计阶段做准备。

