INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3449, null, null, null, null, '论软件架构设计方法', '请结合你参与过的软件项目，论述软件架构设计的重要性。重点阐述你所采用的架构风格及其选择理由，说明该架构风格在项目中的具体应用，以及在实际项目中遇到的问题和解决方案。要求：摘要在300字左右，正文不少于2000字。', '[]', '', '', 6, 2, 'mock', '2026-03-29 16:58:44', '2026-03-29 16:58:44', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3450, null, null, null, null, '论微服务架构的设计与实践', '请论述微服务架构的核心概念与优势，结合你参与的实际项目，说明如何进行微服务拆分、服务间通信方式的选择、数据一致性保障措施及服务治理实践经验。要求：摘要在300字左右，正文不少于2000字。', '[]', '', '', 6, 2, 'mock', '2026-03-29 16:58:44', '2026-03-29 16:58:44', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3451, null, null, null, null, '论软件可靠性设计', '请结合你参与的软件项目，论述软件可靠性设计的重要性及具体实施方法。重点阐述你在项目中采用的容错设计、冗余设计、检验点设置等可靠性保障手段，以及这些措施的实际效果。要求：摘要在300字左右，正文不少于2000字。', '[]', '', '', 6, 2, 'mock', '2026-03-29 16:58:44', '2026-03-29 16:58:44', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3452, null, null, null, null, '论云原生应用架构设计', '云原生架构是现代软件系统的重要发展方向。请结合你参与的项目，论述云原生架构的核心理念（容器化、微服务、DevOps、持续交付），说明你是如何将传统应用迁移至云原生架构或在新项目中采用云原生架构的，以及在该过程中遇到的挑战和解决方案。要求：摘要在300字左右，正文不少于2000字。', '[]', '', '', 6, 2, 'mock', '2026-03-29 16:58:44', '2026-03-29 16:58:44', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3453, null, null, null, null, '论系统需求分析方法', '结合你参与的具体软件项目，论述系统需求分析的重要性，重点阐述你所采用的需求获取方法、需求分析技术以及需求规格说明书的编写规范，并说明你在项目中如何有效地识别、跟踪和管理需求变更。要求：摘要在300字左右，正文不少于2000字。', '[]', '', '', 6, 2, 'mock', '2026-03-29 16:58:44', '2026-03-29 16:58:44', 0, 0);
INSERT INTO aisoftoj.question (id, front_mock_id, subject_name, category_name, paper_year, name, intro, options, answer, analysis, question_type, difficulty, source_type, create_time, update_time, is_deleted, read_ct) VALUES (3454, null, null, null, null, '论信息系统的数据架构设计', '数据架构是信息系统建设的核心基础。请结合你参与的信息系统项目，论述数据架构设计的方法与实践，包括数据模型设计、数据存储选型、数据访问策略、数据安全与质量保障等方面，以及在项目实施中遇到的典型问题和应对措施。要求：摘要在300字左右，正文不少于2000字。', '[]', '', '', 6, 2, 'mock', '2026-03-29 16:58:44', '2026-03-29 16:58:44', 0, 0);
